ALTER TABLE main.bi_output.bi_output_vg_customer_first_dates ALTER COLUMN `PlayerStatusID` COMMENT 'Compliance and trading account status. FK to Dictionary.PlayerStatus. 1=Active/Registered (97.5% of accounts); other values indicate restricted, closed, banned, or special states. Default=0. (Tier 1 ג€” Customer.CustomerStatic)';
ALTER TABLE main.bi_output.bi_output_vg_customer_first_dates ALTER COLUMN `PlayerStatusReasonID` COMMENT 'Reason code for current PlayerStatusID. Provides the why behind a non-Active status. (Tier 1 ג€” Customer.CustomerStatic)';
ALTER TABLE main.bi_output.bi_output_vg_customer_first_dates ALTER COLUMN `PlayerStatusSubReasonID` COMMENT 'Sub-reason code for PlayerStatus (hierarchical). FK to Dictionary.PlayerStatusSubReasons. Added 2022 (COINF-1989). (Tier 1 ג€” Customer.CustomerStatic)';
ALTER TABLE main.bi_output.bi_output_vg_customer_first_dates ALTER COLUMN `Portfolio_Only` COMMENT 'Portfolio-only (has portfolio, not actively trading). From Function_Population_Portfolio_Only. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.bi_output.bi_output_vg_customer_first_dates ALTER COLUMN `RealCID` COMMENT 'Customer ID - platform-internal primary key. Assigned at registration. Unique within etoro DB. Used as the universal customer identifier across all tables. (Tier 1 ג€” Customer.CustomerStatic)';
ALTER TABLE main.bi_output.bi_output_vg_customer_first_dates ALTER COLUMN `RegistrationDate` COMMENT 'Account registration date (renamed from Registered). Default=getdate(). (Tier 1 ג€” Customer.CustomerStatic)';
ALTER TABLE main.bi_output.bi_output_vg_customer_first_dates ALTER COLUMN `RegulationID` COMMENT 'Regulatory entity governing this account. FK to Dictionary.Regulation. Top values: CySEC=7.39M, BVI=7.30M, FCA=1.17M. Changes trigger RegulationChangeDate update. (Tier 1 ג€” BackOffice.Customer)';
ALTER TABLE main.bi_output.bi_output_vg_customer_first_dates ALTER COLUMN `TP_FTD_Date` COMMENT 'Trading Platform first-time deposit datetime. From Dim_Customer.FirstDepositDate where FTDPlatformID=1. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.bi_output.bi_output_vg_customer_first_dates ALTER COLUMN `TP_FTDA` COMMENT 'Trading Platform first-time deposit amount in USD. From Dim_Customer.FirstDepositAmount where FTDPlatformID=1. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.bi_output.bi_output_vg_customer_first_dates ALTER COLUMN `VerificationLevelID` COMMENT 'KYC verification level. FK to Dictionary.VerificationLevel. Values: 0=unverified (34.2%), 1=partial (12.4%), 2=intermediate (6.2%), 3=fully verified (47.1%). Default=0. (Tier 1 ג€” BackOffice.Customer)';

