ALTER TABLE main.bi_output.bi_output_vg_revenue ALTER COLUMN `AccountStatusID` COMMENT 'Account enabled/suspended status. DEFAULT 0. Distribution: 1=93.2% (Active), 0=6.1%, 2=0.9% (Inactive). Source: Ext_FSC_Real_Customer_Customer.AccountStatusID (CC). FK to Dim_AccountStatus. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.bi_output.bi_output_vg_revenue ALTER COLUMN `AccountTypeID` COMMENT 'Account type (e.g., 7=Employee, 9=excluded type, 2=real account). DEFAULT 0. Source: Ext_FSC_BackOffice_Customer.AccountTypeID (BO). FK to Dim_AccountType. Used in IsCreditReportValidCB logic. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.bi_output.bi_output_vg_revenue ALTER COLUMN `AffiliateID` COMMENT 'Affiliate (partner) ID under which the customer was acquired (renamed from SerialID). FK to BackOffice.Affiliate. NULL for direct/organic registrations. (Tier 1 ג€” Customer.CustomerStatic)';
ALTER TABLE main.bi_output.bi_output_vg_revenue ALTER COLUMN `Amount` COMMENT 'Revenue amount in USD. `SUM(fee_column)` aggregated per CID ֳ— Metric ֳ— flags group. Positive = revenue, negative possible for dividends paid out. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output.bi_output_vg_revenue ALTER COLUMN `CitizenshipCountryID` COMMENT 'Country of citizenship (may differ from CountryID/residence). FK to Dictionary.Country. Added 2018 for enhanced KYC. (Tier 1 ג€” Customer.CustomerStatic)';
ALTER TABLE main.bi_output.bi_output_vg_revenue ALTER COLUMN `CommunicationLanguageID` COMMENT 'Preferred communication language (may differ from interface language). DEFAULT 0. Source: Ext_FSC_Real_Customer_Customer.CommunicationLanguageID (CC). FK to Dim_Language. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.bi_output.bi_output_vg_revenue ALTER COLUMN `CountAsActiveTrade` COMMENT 'Active trade indicator. `CASE WHEN ActionTypeID IN (1,39) AND ISNULL(IsAirDrop,0) = 0 THEN 1 ELSE 0 END`; `ISNULL(...,0)`. Only 1 for non-airdrop commission rows. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output.bi_output_vg_revenue ALTER COLUMN `CountryID` COMMENT 'Customer''s registered country. DEFAULT 0. Source: Ext_FSC_Real_Customer_Customer.CountryID (CC). FK to Dim_Country. Key filter for valid customer segmentation (CountryID=250 excluded). (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.bi_output.bi_output_vg_revenue ALTER COLUMN `Date` COMMENT 'Calendar date. `@date` SP parameter for main INSERT; computed from DateID for Staking. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output.bi_output_vg_revenue ALTER COLUMN `DateID` COMMENT 'Date key in YYYYMMDD format. DELETE/INSERT partition key. Direct from revenue functions (except Staking: lagged one month via `DATEADD(MONTH,1,...)`). (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output.bi_output_vg_revenue ALTER COLUMN `GuruStatusID` COMMENT 'Popular Investor (Guru) program status. DEFAULT 0. Source: Ext_FSC_BackOffice_Customer.GuruStatusID (BO). FK to Dim_GuruStatus. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.bi_output.bi_output_vg_revenue ALTER COLUMN `InstrumentTypeID` COMMENT 'Instrument asset class. From revenue functions. `ISNULL(...,-1)` ג€” sentinel -1 for account-level fees (CashoutFee, ConversionFee, DormantFee, InterestFee). (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output.bi_output_vg_revenue ALTER COLUMN `IsCopy` COMMENT 'Copy-trade flag. `CASE WHEN MirrorID > 0 THEN 1 ELSE 0 END`; `ISNULL(...,-1)`. C2F forced to -1. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output.bi_output_vg_revenue ALTER COLUMN `IsPI` COMMENT 'Popular Investor (Guru) program status. DEFAULT 0. Source: Ext_FSC_BackOffice_Customer.GuruStatusID (BO). FK to Dim_GuruStatus. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.bi_output.bi_output_vg_revenue ALTER COLUMN `IsSettled` COMMENT '1 = real asset, 0 = CFD asset. (Tier 5 ג€” Expert Review)';
ALTER TABLE main.bi_output.bi_output_vg_revenue ALTER COLUMN `LanguageID` COMMENT 'Customer''s preferred interface language. DEFAULT 0. Source: Ext_FSC_Real_Customer_Customer.LanguageID (CC). FK to Dim_Language. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.bi_output.bi_output_vg_revenue ALTER COLUMN `Metric` COMMENT 'Revenue stream identifier. 18 distinct values: ''FullCommission'', ''Commission'', ''RollOverFee'', ''Dividends'', ''SDRT'', ''TicketFee'', ''TicketFeeByPercent'', ''CashoutFeeExclRedeem'', ''ConversionFee'', ''DormantFee'', ''InterestFee'', ''TransferCoinFee'', ''AdminFee'', ''SpotPriceAdjustment'', ''ShareLending'', ''CryptoToFiatFee'', ''StakingLagOneMonth'', ''Options_PFOF''. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output.bi_output_vg_revenue ALTER COLUMN `PlayerLevelID` COMMENT 'Account tier: 4=demo, other values=real tiers. DEFAULT 0. Source: Ext_FSC_Real_Customer_Customer.PlayerLevelID (CC). FK to Dim_PlayerLevel. Critical for IsValidCustomer (PlayerLevelID=4 excluded). (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.bi_output.bi_output_vg_revenue ALTER COLUMN `PlayerStatusID` COMMENT 'Customer lifecycle status (e.g., Active, Blocked, Pending). DEFAULT 0. Source: Ext_FSC_Real_Customer_Customer.PlayerStatusID (CC). FK to Dim_PlayerStatus. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.bi_output.bi_output_vg_revenue ALTER COLUMN `PlayerStatusReasonID` COMMENT 'Reason code for the current PlayerStatusID (e.g., why account was blocked). DEFAULT 0. Source: Ext_FSC_Real_Customer_Customer.PlayerStatusReasonID (CC). FK to Dim_PlayerStatusReasons. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.bi_output.bi_output_vg_revenue ALTER COLUMN `PlayerStatusSubReasonID` COMMENT 'Sub-reason code for PlayerStatus (more granular than PlayerStatusReasonID). DEFAULT 0. Source: Ext_FSC_Real_Customer_Customer.PlayerStatusSubReasonID (CC). FK to Dim_PlayerStatusSubReasons. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.bi_output.bi_output_vg_revenue ALTER COLUMN `RealCID` COMMENT 'Customer identifier. Distribution key. From revenue functions (CID renamed to RealCID for some). (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output.bi_output_vg_revenue ALTER COLUMN `RegulationID` COMMENT 'Customer''s assigned regulatory jurisdiction. DEFAULT 0. Sourced from Ext_FSC_BackOffice_RegulationChangeLog.ToRegulationID ג€” end-of-day change. See ֲ§2.4. FK to Dim_Regulation. (Tier 2 - SP_Fact_SnapshotCustomer)';
