ALTER TABLE main.bi_output.bi_output_vg_volume_amount ALTER COLUMN `Date` COMMENT 'Calendar date. `CONVERT(DATE, CONVERT(VARCHAR(8), ftv.DateID), 112)`. Derived from DateID in SP. (Tier 2 ג€” SP_DDR_Fact_Trading_Volumes_And_Amounts)';
ALTER TABLE main.bi_output.bi_output_vg_volume_amount ALTER COLUMN `DateID` COMMENT 'Date key in YYYYMMDD format. DELETE/INSERT partition key. Direct from `Function_Trading_Volume_PositionLevel.DateID` (open or close date). (Tier 2 ג€” SP_DDR_Fact_Trading_Volumes_And_Amounts)';
ALTER TABLE main.bi_output.bi_output_vg_volume_amount ALTER COLUMN `GuruStatusID` COMMENT 'Popular Investor (Guru) program status. DEFAULT 0. Source: Ext_FSC_BackOffice_Customer.GuruStatusID (BO). FK to Dim_GuruStatus. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.bi_output.bi_output_vg_volume_amount ALTER COLUMN `InstrumentTypeID` COMMENT 'Instrument asset class. From `Dim_Instrument.InstrumentTypeID` via function. (Tier 2 ג€” SP_DDR_Fact_Trading_Volumes_And_Amounts)';
ALTER TABLE main.bi_output.bi_output_vg_volume_amount ALTER COLUMN `InvestedAmountClosed` COMMENT 'Aggregated invested amount from position closes. `SUM(ftv.InvestedAmountClosed)`. Source: `CAST(Dim_Position.Amount AS FLOAT)` on close legs. (Tier 2 ג€” SP_DDR_Fact_Trading_Volumes_And_Amounts)';
