ALTER TABLE main.bi_output.bi_output_vg_volume_amount ALTER COLUMN `IsCopy` COMMENT 'Copy-trade flag. `CASE WHEN MirrorID > 0 THEN 1 ELSE 0 END` in function. (Tier 2 ג€” SP_DDR_Fact_Trading_Volumes_And_Amounts)';
ALTER TABLE main.bi_output.bi_output_vg_volume_amount ALTER COLUMN `IsCopyFund` COMMENT 'Smart Portfolio flag. `CASE WHEN BI_DB_CopyFund_Positions.PositionID IS NOT NULL THEN 1 ELSE 0 END` in function. (Tier 2 ג€” SP_DDR_Fact_Trading_Volumes_And_Amounts)';
ALTER TABLE main.bi_output.bi_output_vg_volume_amount ALTER COLUMN `IsFuture` COMMENT 'Futures contract flag. Direct from function ג†’ `Dim_Instrument.IsFuture`. (Tier 2 ג€” SP_DDR_Fact_Trading_Volumes_And_Amounts)';
ALTER TABLE main.bi_output.bi_output_vg_volume_amount ALTER COLUMN `IsLeverage` COMMENT 'Leverage flag. `CASE WHEN ftv.Leverage > 1 THEN 1 ELSE 0 END`. Note: named `IsLeverage` (not `IsLeveraged`). (Tier 2 ג€” SP_DDR_Fact_Trading_Volumes_And_Amounts)';
