ALTER TABLE main.bi_output.bi_output_vg_volume_amount ALTER COLUMN `IsOpenedFromIBAN` COMMENT 'Position opened from eMoney IBAN flag. `CASE WHEN BI_DB_Positions_Opened_From_IBAN.PositionID IS NOT NULL THEN 1 ELSE 0 END` in function. **DDL is varchar(100), stores ''0''/''1'' as strings.** (Tier 2 ג€” SP_DDR_Fact_Trading_Volumes_And_Amounts)';
ALTER TABLE main.bi_output.bi_output_vg_volume_amount ALTER COLUMN `IsPI` COMMENT 'Popular Investor (Guru) program status. DEFAULT 0. Source: Ext_FSC_BackOffice_Customer.GuruStatusID (BO). FK to Dim_GuruStatus. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.bi_output.bi_output_vg_volume_amount ALTER COLUMN `IsRecurring` COMMENT 'Recurring investment flag. `CASE WHEN BI_DB_RecurringInvestment_Positions.PositionID IS NOT NULL THEN 1 ELSE 0 END` in function. (Tier 2 ג€” SP_DDR_Fact_Trading_Volumes_And_Amounts)';
ALTER TABLE main.bi_output.bi_output_vg_volume_amount ALTER COLUMN `IsSettled` COMMENT '1 = real asset, 0 = CFD asset. (Tier 5 ג€” Expert Review)';
