ALTER TABLE main.bi_output.bi_output_vg_volume_amount ALTER COLUMN `NetInvestedAmount` COMMENT 'Net investment flow. `SUM(ftv.NetInvestedAmount)`. Per position: `InvestedAmountOpen - InvestedAmountClosed`. Positive = net new investment. (Tier 2 ג€” SP_DDR_Fact_Trading_Volumes_And_Amounts)';
