ALTER TABLE main.bi_output.bi_output_vg_volume_amount ALTER COLUMN `RegulationID` COMMENT 'Customer''s assigned regulatory jurisdiction. DEFAULT 0. Sourced from Ext_FSC_BackOffice_RegulationChangeLog.ToRegulationID ג€” end-of-day change. See ֲ§2.4. FK to Dim_Regulation. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.bi_output.bi_output_vg_volume_amount ALTER COLUMN `TotalVolume` COMMENT 'Combined open + close volume. `SUM(ftv.TotalVolume)`. Per position: `ISNULL(VolumeOpen,0) + ISNULL(VolumeClose,0)`. (Tier 2 ג€” SP_DDR_Fact_Trading_Volumes_And_Amounts)';
