ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `Approved` COMMENT 'Legacy approval flag, superseded by PaymentStatusID=2. NULL for most modern records. Retained for backward compatibility. (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `BaseExchangeRate` COMMENT 'Reference exchange rate before fee markup. Fee spread = ExchangeRate - BaseExchangeRate. Added by Adi (19/09/2019). (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `BonusAmount` COMMENT 'Bonus amount credited with this deposit. NULL when no bonus applies. (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `BonusErrorCode` COMMENT 'Error code when bonus processing fails (BonusStatusID=2). NULL when bonus succeeds or not attempted. (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `BonusStatusID` COMMENT 'Promotional bonus status. Values: 0=New, 1=Approved, 2=Declined, 3=Reverted. Only 239 non-zero records in production. (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `CID` COMMENT 'Customer ID. Identifies the eToro customer who made this deposit. References DWH_dbo.Dim_Customer. (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `ClearingHouseEffectiveDate` COMMENT 'Settlement date assigned by the clearing house. NULL for instant payment methods. (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `Commission` COMMENT 'Commission charged on this deposit. Default 0 in production. (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `CurrencyID` COMMENT 'Currency of the deposit amount. References DWH_dbo.Dim_Currency. 1=USD, 2=EUR, 3=GBP, etc. (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `DepositID` COMMENT 'Primary distribution key (HASH). Uniquely identifies each deposit attempt. PK in production (Billing.Deposit.DepositID IDENTITY). Clustered index key in DWH. (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `DepotID` COMMENT 'Acquirer/gateway configuration used for this deposit. Validated at insert against DepotToCurrency in production. (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `DocumentRequired` COMMENT 'Whether documentation was required for this deposit/funding instrument. Sourced from Billing.Funding.DocumentRequired. (Tier 2 ג€” SP_Fact_BillingDeposit_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `ExchangeFee` COMMENT 'Exchange fee in provider-specific integer encoding (basis points). Added by Adi (19/02/2019). (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `ExchangeRate` COMMENT 'Exchange rate from deposit currency to USD at processing time. Cannot be 0 in production. (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `ExpirationDateID` COMMENT 'Integer date ID derived from ExpirationDateAsString XML attribute via a complex formula in SP. Represents card expiration date as YYYYMMDD. NC index key. (Tier 2 ג€” SP_Fact_BillingDeposit_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `ExTransactionID` COMMENT 'External (payment provider) transaction ID. Used for provider-side reconciliation and dispute resolution. (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `FlowID` COMMENT 'Deposit UX flow variant. NULL=default (98.9%), 1=new flow (0.97%), 3=specific variant. Added PAYIL-8362, 2024-04-18. (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `FundingID` COMMENT 'Payment instrument (credit card, bank account, e-wallet) used for this deposit. References Billing.Funding. (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `FundingTypeID` COMMENT 'Type of payment instrument. Sourced from Billing.Funding.FundingTypeID (not from Billing.Deposit directly). Categorizes the deposit by payment method (credit card, wire, ACH, etc.). (Tier 2 ג€” SP_Fact_BillingDeposit_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `FunnelID` COMMENT 'Marketing funnel ID. FK to Dictionary.Funnel. (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `IPAddress` COMMENT 'Customer IP address at deposit time, as a 32-bit integer. Used for fraud detection. (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `IsAftEligibleAsBool` COMMENT 'Whether this deposit was eligible for AFT processing. Sourced from Billing.Funding. (Tier 2 ג€” SP_Fact_BillingDeposit_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `IsAftProcessedAsBool` COMMENT 'Whether this deposit was actually processed via AFT. Sourced from Billing.Funding or Billing.Deposit. (Tier 2 ג€” SP_Fact_BillingDeposit_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `IsAftSupportedAsBool` COMMENT 'Whether Account Funding Transaction (AFT) is supported by this funding instrument. Sourced from Billing.Funding. (Tier 2 ג€” SP_Fact_BillingDeposit_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `IsFTD` COMMENT 'First Time Deposit flag. 1=this was the customer''s very first approved deposit (drives marketing attribution). 0=repeat deposit or ineligible type. ~60.6% of deposits are FTD=1 in Billing.Deposit. Stored as int in DWH (vs. bit in production). (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `IsRecurring` COMMENT '1=deposit is part of a recurring schedule (OUTER APPLY on Billing.RecurringDeposit). 0=one-time deposit. (Tier 2 ג€” SP_Fact_BillingDeposit_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `IsRefundExcluded` COMMENT 'Whether this deposit is excluded from refund eligibility. Sourced from Billing.Funding.IsRefundExcluded. (Tier 2 ג€” SP_Fact_BillingDeposit_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `IsSetBalanceCompleted` COMMENT '1=account crediting (Billing.AmountAdd) completed for this deposit. Added DBA-646. (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `ManagerID` COMMENT 'Operations manager who processed this deposit. 0=automated. (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `MatchStatusID` COMMENT 'PSP reconciliation match status. Default 0=Unmatched; 3=Matched. Used for provider reconciliation workflows. (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `MerchantAccountID` COMMENT 'Merchant account legal entity for regulatory routing. Added with DBA-646. (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `ModificationDate` COMMENT 'UTC timestamp of the most recent modification to this deposit record. Used by ETL for incremental detection. (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `ModificationDateID` COMMENT 'ETL key. Integer YYYYMMDD derived from ModificationDate (CONVERT(INT, date)). Used for rolling-window DELETE+INSERT. (Tier 2 ג€” SP_Fact_BillingDeposit_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `PaymentDate` COMMENT 'UTC timestamp when the deposit was submitted (set at INSERT in production). Not the approval time. (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `PaymentGeneration` COMMENT 'Payment infrastructure generation: 0=Gen0 (7.7%), 1=Gen1 (92%). Added 2020-04-19. (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `PaymentStatusID` COMMENT 'Current deposit status. Key values: 1=New, 2=Approved (73%), 3=Decline, 5=InProcess, 11=Chargeback, 12=Refund, 13=Pending, 35=DeclineByRRE (10.2%). Full 39-value enum in upstream wiki. NC index key. (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `PlatformID` COMMENT 'Device/platform the customer used for this deposit. NOT from Billing.Deposit ג€” enriched via second ETL pass: JOIN Fact_CustomerAction ON SessionID WHERE ActionTypeID=14. NULL if no matching session action found. References DWH_dbo.Dim_Platform. (Tier 2 ג€” SP_Fact_BillingDeposit_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `ProcessorValueDate` COMMENT 'Value date from the payment processor. Mandatory for offline/wire deposits. NULL for instant payment methods. (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `ProcessRegulationID` COMMENT 'Regulatory entity/jurisdiction: 1=Cyprus/EU (~63%), 2=UK/FCA (~16%), 4=AU (~2.5%), others for ASIC etc. Added DBA-646, 2021-09-05. (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `ProtocolMIDSettingsID` COMMENT 'Merchant ID configuration profile. Default 0=no specific MID. Added 2018-10-24. (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `RefundVerificationCode` COMMENT 'Verification code for refund correlation. Set by UpdateRefundDetails. NULL for non-refunded deposits. (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `RiskManagementStatusID` COMMENT 'Result of the pre-processing risk management check. 69 distinct risk reason codes. NULL=no risk check recorded. Key codes: 1=Success, 35=DeclineByRRE, 47=ML, 49=CustomerToFundingViolation. (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `RoutingReasonID` COMMENT 'Reason code for routing path selection. Values 1-8; 3=most common (~29%). ~31% NULL for legacy records. Added PAYUS-3061, 2021-06-15. (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `SessionID` COMMENT 'Application session ID. Used for PlatformID enrichment via Fact_CustomerAction JOIN (second ETL pass). (Tier 1 ג€” upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_output.vg_fact_billingdeposit_for_genie ALTER COLUMN `UpdateDate` COMMENT 'ETL load timestamp. GETDATE() at SP execution. Not from production. (Tier 2 ג€” SP_Fact_BillingDeposit_DL_To_Synapse)';

