-- ----------------------------------------
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `AccountCurrencyID` COMMENT 'Customer eToro account currency, if different from CurrencyID. Used when account and withdrawal currencies differ. FK to Dim_Currency. (Tier 1 ג€” Billing.Withdraw)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `AccountIDAsDecimal` COMMENT 'Funding instrument account ID (decimal form). Extracted from bf.FundingData XML only. (Tier 2 ג€” SP_Fact_BillingWithdraw_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `AccountIDAsString` COMMENT 'Payment account identifier. COALESCE: prefers wtf.WithdrawData XML, falls back to bf.FundingData XML. (Tier 2 ג€” SP_Fact_BillingWithdraw_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `AccountNameAsString` COMMENT 'Account holder name on the funding instrument. Extracted from bf.FundingData XML only. (Tier 2 ג€” SP_Fact_BillingWithdraw_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `AccountTypeAsString` COMMENT 'Account type (checking, savings, etc.). Extracted from bf.FundingData XML only. (Tier 2 ג€” SP_Fact_BillingWithdraw_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `ACHBankAccountIDAsInteger` COMMENT 'ACH bank account identifier for US bank transfers. Extracted from wtf.WithdrawData XML only. (Tier 2 ג€” SP_Fact_BillingWithdraw_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `Amount_Withdraw` COMMENT 'Gross withdrawal amount in CurrencyID denomination. Renamed from Amount to disambiguate from WithdrawToFunding Amount. (Tier 1 ג€” Billing.Withdraw)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `Amount_WithdrawToFunding` COMMENT 'Payout amount in ProcessCurrencyID currency. Renamed from Amount. For refunds, the amount being refunded to the instrument. (Tier 1 ג€” Billing.WithdrawToFunding)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `Approved` COMMENT 'Whether the withdrawal has received required approval. 1=Approved, 0=Pending approval. DEFAULT=0. DWH note: CAST from bit to int. (Tier 1 ג€” Billing.Withdraw)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `BankAccountAsString` COMMENT 'Bank account number for wire/bank transfers. Extracted from bf.FundingData XML only. (Tier 2 ג€” SP_Fact_BillingWithdraw_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `BankAddressAsString` COMMENT 'Bank address for wire transfers. Extracted from bf.FundingData XML only. (Tier 2 ג€” SP_Fact_BillingWithdraw_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `BankCodeAsString` COMMENT 'Bank code (national bank identifier). Extracted from bf.FundingData XML only. (Tier 2 ג€” SP_Fact_BillingWithdraw_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `BankDetailsAccountIDAsString` COMMENT 'Bank details account reference. Extracted from bf.FundingData XML only. (Tier 2 ג€” SP_Fact_BillingWithdraw_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `BankIDAsInteger` COMMENT 'Bank identifier (integer form). Extracted from bf.FundingData XML only. (Tier 2 ג€” SP_Fact_BillingWithdraw_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `BankIDAsString` COMMENT 'Bank identifier (string form). Extracted from bf.FundingData XML only. (Tier 2 ג€” SP_Fact_BillingWithdraw_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `BankName` COMMENT 'Issuing bank name looked up from BIN code via post-load enrichment JOIN to Dim_CountryBin.IssuingBank. NULL when BinCodeAsString is NULL or BIN code not found. Distinct from BankNameAsString (#69) which comes from the funding XML. (Tier 2 ג€” SP_Fact_BillingWithdraw)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `BankNameAsString` COMMENT 'Bank name from the bf.FundingData XML. Distinct from the enriched BankName (#82) which comes from Dim_CountryBin BIN-code lookup, and ClientBankNameAsString (#44) which is COALESCE from wtf/bf. (Tier 2 ג€” SP_Fact_BillingWithdraw_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `BaseExchangeRate` COMMENT 'Reference exchange rate before fee markup. Spread = ExchangeRate minus BaseExchangeRate. (Tier 1 ג€” Billing.WithdrawToFunding)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `BinCodeAsString` COMMENT 'Bank Identification Number (first 6-8 digits of card). COALESCE from wtf/bf XML. CAST to INT for JOIN with Dim_CountryBin to populate BankName and CardCategory. (Tier 2 ג€” SP_Fact_BillingWithdraw_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `BinCountryIDAsInteger` COMMENT 'Country associated with the BIN code. COALESCE from wtf/bf XML. FK to Dim_Country after CAST to INT. (Tier 2 ג€” SP_Fact_BillingWithdraw_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `BSBNumberAsString` COMMENT 'Bank State Branch number for Australian bank transfers. Extracted from wtf.WithdrawData XML only. (Tier 2 ג€” SP_Fact_BillingWithdraw_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `CardCategory` COMMENT 'Card category (Debit, Credit, Prepaid, etc.) looked up from BIN code via post-load enrichment JOIN to Dim_CountryBin.CardCategory. NULL when BIN code not found. (Tier 2 ג€” SP_Fact_BillingWithdraw)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `CardNumberAsString` COMMENT 'Masked card number (last 4 digits typically visible). Extracted from bf.FundingData XML only. Source column FundingData is masked with FUNCTION=''default()'' in production. (Tier 2 ג€” SP_Fact_BillingWithdraw_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `CardTypeIDAsInteger` COMMENT 'Card type identifier (Visa, Mastercard, etc.). COALESCE from wtf/bf XML. FK to Dim_CardType after CAST to INT. (Tier 2 ג€” SP_Fact_BillingWithdraw_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `CashoutModeID` COMMENT 'Mode of withdrawal execution: 1=Standard (75.2%), NULL=legacy (17%), 2=Alternate e.g. eToroMoney/ACH (4%), 0=Unknown/fallback (3.8%). FK to Dim_CashoutMode. (Tier 1 ג€” Billing.WithdrawToFunding)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `CashoutReasonID` COMMENT 'Internal reason code for the withdrawal decision (e.g., why cancelled or flagged). FK to Dim_CashoutReason. (Tier 1 ג€” Billing.Withdraw)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `CashoutStatusID_Funding` COMMENT 'Execution-level status of the payment leg. FK to Dim_CashoutStatus. Values: 3=Processed (31.5%), 4=Canceled (67.7%), 14=Pending Review, 17=Partially Reversed. Renamed from CashoutStatusID. (Tier 1 ג€” Billing.WithdrawToFunding)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `CashoutStatusID_Withdraw` COMMENT 'Withdrawal request-level status. FK to Dim_CashoutStatus. 10 distinct values: 1=Pending, 2=InProcess, 3=Processed, 4=Cancelled. Renamed from CashoutStatusID. (Tier 1 ג€” Billing.Withdraw)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `CashoutTypeID` COMMENT 'Categorizes the type of payment execution: 1=Cashout (standard withdrawal, 69%), 2=Refund (refund of a prior deposit, 31%). (Tier 1 ג€” Billing.WithdrawToFunding)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `CID` COMMENT 'Customer ID. FK to Customer.CustomerStatic. (Tier 1 ג€” Billing.Withdraw)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `CityAsString` COMMENT 'City from the payment execution data. Extracted from wtf.WithdrawData XML only. (Tier 2 ג€” SP_Fact_BillingWithdraw_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `ClientAddressAsString` COMMENT 'Client address from the payment execution data. Extracted from wtf.WithdrawData XML only. (Tier 2 ג€” SP_Fact_BillingWithdraw_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `ClientBankNameAsString` COMMENT 'Client''s bank name. COALESCE from wtf/bf XML. Distinct from BankNameAsString (#67) which is from bf.FundingData only, and BankName (#82) which is post-load enrichment from Dim_CountryBin. (Tier 2 ג€” SP_Fact_BillingWithdraw_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `ClientWithdrawReasonID` COMMENT 'Customer-selected reason for the withdrawal (e.g., taking profits, funds needed, dissatisfied). FK to Dim_ClientWithdrawReason. (Tier 1 ג€” Billing.Withdraw)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `Comment` COMMENT 'Operations comment on the withdrawal request. Free-text field populated by back-office staff. (Tier 1 ג€” Billing.Withdraw)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `Commission` COMMENT 'Broker commission on this withdrawal. DEFAULT=0. Typically 0 for retail customers. (Tier 1 ג€” Billing.Withdraw)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `CountryIDAsInteger` COMMENT 'Country identifier from payment data. COALESCE from wtf/bf XML. FK to Dim_Country after CAST to INT. (Tier 2 ג€” SP_Fact_BillingWithdraw_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `CryptoCodeAsString` COMMENT 'Cryptocurrency code/address for crypto withdrawals. Extracted from bf.FundingData XML only. (Tier 2 ג€” SP_Fact_BillingWithdraw_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `CurrencyID` COMMENT 'Currency of the withdrawal amount. FK to Dictionary.Currency. (Tier 1 ג€” Billing.Withdraw)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `CustomerAddressAsString` COMMENT 'Customer address from the funding instrument record. Extracted from bf.FundingData XML only. (Tier 2 ג€” SP_Fact_BillingWithdraw_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `CustomerNameAsString` COMMENT 'Customer name from the funding instrument record. Extracted from bf.FundingData XML only. (Tier 2 ג€” SP_Fact_BillingWithdraw_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `DepositID` COMMENT 'For refund legs (CashoutTypeID=2): references the source Billing.Deposit being refunded. Value 0 is null-equivalent for cashout legs. (Tier 1 ג€” Billing.WithdrawToFunding)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `DepotID` COMMENT 'Which Billing.Depot (acquirer/gateway configuration) processed this payment leg. FK to Dim_BillingDepot. (Tier 1 ג€” Billing.WithdrawToFunding)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `EmailAsString` COMMENT 'Email address associated with the funding instrument (e.g., PayPal email). Extracted from bf.FundingData XML only. (Tier 2 ג€” SP_Fact_BillingWithdraw_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `ErrorCodeAsString` COMMENT 'Provider error code if the payment leg failed or was rejected. Extracted from wtf.WithdrawData XML only. NULL for successful transactions. (Tier 2 ג€” SP_Fact_BillingWithdraw_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `ExchangeFee` COMMENT 'Exchange fee in provider-specific integer units. (Tier 1 ג€” Billing.WithdrawToFunding)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `ExchangeRate` COMMENT 'Exchange rate applied to convert from withdrawal currency to ProcessCurrencyID. NULL for same-currency payouts. (Tier 1 ג€” Billing.WithdrawToFunding)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `ExpirationDateAsString` COMMENT 'Card expiration date as raw string from wtf.WithdrawData XML. Format varies by provider (MMYY, MM/YY, etc.). See ExpirationDateID (#69) for the normalized integer version. (Tier 2 ג€” SP_Fact_BillingWithdraw_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `ExpirationDateID` COMMENT 'Card expiration date as normalized integer key: 200000 + YY*100 + MM for valid dates; 190001 for NULL or strings shorter than 4 characters. NCI index on this column. Computed from bf.FundingData ExpirationDateAsString XML field. (Tier 2 ג€” SP_Fact_BillingWithdraw_DL_To_Synapse)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `Fee` COMMENT 'Platform fee charged for this withdrawal. Subtracted from the gross Amount_Withdraw. (Tier 1 ג€” Billing.Withdraw)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `FlowID` COMMENT 'Processing flow identifier. NULL=legacy, 0=standard, 2=eToroMoney (triggers MoveMoneyReasonID=5), 3=alternate (triggers MoveMoneyReasonID=6). (Tier 1 ג€” Billing.Withdraw)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `FundingID` COMMENT 'FK to Billing.Funding ג€” the payment instrument to which the withdrawal is paid. NULL if no specific instrument selected. (Tier 1 ג€” Billing.Withdraw)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `FundingTypeID_Funding` COMMENT 'Payment method type of the funding instrument receiving the payout. Renamed from FundingTypeID on Billing.Funding. 34 distinct types (Visa/MC/Neteller/PayPal/Wire/eToroMoney/etc.). FK to Dim_FundingType. (Tier 1 ג€” Billing.Funding)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `FundingTypeID_Withdraw` COMMENT 'Payment method type of the withdrawal request (Visa/Wire/Neteller/eToroMoney/etc.). 26 distinct values in production. Renamed from FundingTypeID to disambiguate from Billing.Funding''s FundingTypeID. (Tier 1 ג€” Billing.Withdraw)';
ALTER TABLE main.bi_output.vg_fact_billingwithdraw_for_genie ALTER COLUMN `IBANCodeAsString` COMMENT 'International Bank Account Number for SEPA/wire transfers. COALESCE from wtf/bf XML. (Tier 2 ג€” SP_Fact_BillingWithdraw_DL_To_Synapse)';
