ALTER TABLE main.bi_output.vg_fact_snapshotcustomer_for_emoney_genie ALTER COLUMN `IsValidCustomer_FromDate_ToDate` COMMENT '1 if the customer is a valid retail customer for analytics purposes. ETL-computed from PlayerLevelID, LabelID, CountryID. See ֲ§2.2. Approx 98% of current rows = 1. (Tier 2 - SP_Fact_SnapshotCustomer)';
