ALTER TABLE main.bi_output.vg_positions_open_closed_iban_tp ALTER COLUMN `SubChannelID` COMMENT 'Sub-channel ID. Populated post-load from SubChannel unify code via AffiliateID mapping. DEFAULT=0. (Tier 2 ג€” SP_Dim_Customer)';
ALTER TABLE main.bi_output.vg_positions_open_closed_iban_tp ALTER COLUMN `VerificationLevelID` COMMENT 'KYC verification level. FK to Dictionary.VerificationLevel. Values: 0=unverified (34.2%), 1=partial (12.4%), 2=intermediate (6.2%), 3=fully verified (47.1%). Default=0. (Tier 1 ג€” BackOffice.Customer)';

