ALTER TABLE main.bi_output.vg_positionsvolumeandattributes_lc4_source ALTER COLUMN `AccountTypeID_as_of_position_date` COMMENT 'Account type (e.g., 7=Employee, 9=excluded type, 2=real account). DEFAULT 0. Source: Ext_FSC_BackOffice_Customer.AccountTypeID (BO). FK to Dim_AccountType. Used in IsCreditReportValidCB logic. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.bi_output.vg_positionsvolumeandattributes_lc4_source ALTER COLUMN `CountryID` COMMENT 'Customer''s registered country. DEFAULT 0. Source: Ext_FSC_Real_Customer_Customer.CountryID (CC). FK to Dim_Country. Key filter for valid customer segmentation (CountryID=250 excluded). (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.bi_output.vg_positionsvolumeandattributes_lc4_source ALTER COLUMN `InstrumentType` COMMENT 'Text label for InstrumentTypeID -- DWH-computed via CASE: 1=Currencies, 2=Commodities, 4=Indices, 5=Stocks, 6=ETF, 10=Crypto Currencies, else=Other. Use InstrumentTypeID for filtering; InstrumentType for display. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.bi_output.vg_positionsvolumeandattributes_lc4_source ALTER COLUMN `SellCurrencyID` COMMENT 'The sell-side (denomination) currency. FK to DWH_dbo.Dim_Currency(CurrencyID). For forex: the quote currency (e.g., USD in EUR/USD). For stocks: the trading denomination currency (USD, EUR, GBX). Only 67 distinct values since many assets share the same denomination. (Tier 1 -- upstream wiki, Trade.Instrument)';

