-- ----------------------------------------
ALTER TABLE main.bi_output.vg_trades ALTER COLUMN `ActionType` COMMENT 'Event type classifier. References `DWH_dbo.Dim_ActionType.ActionTypeID` ג€” JOIN for Name, Category, CategoryID. See Section 2.1 for full mapping. Key filter column ג€” drives which other columns are populated. (Tier 1 ג€” ETL-derived from CreditTypeID/source)';
ALTER TABLE main.bi_output.vg_trades ALTER COLUMN `AmountClose` COMMENT 'Event type classifier. References `DWH_dbo.Dim_ActionType.ActionTypeID` ג€” JOIN for Name, Category, CategoryID. See Section 2.1 for full mapping. Key filter column ג€” drives which other columns are populated. (Tier 1 ג€” ETL-derived from CreditTypeID/source)';
ALTER TABLE main.bi_output.vg_trades ALTER COLUMN `CID` COMMENT 'Real-account Customer ID. HASH distribution key. References `Dim_Customer.RealCID`. Each customer has one real CID. (Tier 1 ג€” Customer.CustomerStatic)';
ALTER TABLE main.bi_output.vg_trades ALTER COLUMN `ClosedTrades` COMMENT 'Event type classifier. References `DWH_dbo.Dim_ActionType.ActionTypeID` ג€” JOIN for Name, Category, CategoryID. See Section 2.1 for full mapping. Key filter column ג€” drives which other columns are populated. (Tier 1 ג€” ETL-derived from CreditTypeID/source)';
ALTER TABLE main.bi_output.vg_trades ALTER COLUMN `Date` COMMENT 'UTC timestamp when the action occurred. For position opens: when position was opened. For logins: login time. For credits: when the credit was recorded. (Tier 1 ג€” source-dependent)';
ALTER TABLE main.bi_output.vg_trades ALTER COLUMN `FTDDate` COMMENT 'Date of first deposit. DEFAULT=''19000101''. Updated from CustomerFinanceDB FTD data with FTDRecoveryDate logic. (Tier 2 ג€” SP_Dim_Customer)';
ALTER TABLE main.bi_output.vg_trades ALTER COLUMN `InstrumentDisplayName` COMMENT 'User-facing instrument display name from Trade.InstrumentMetaData. More descriptive than Name (e.g., ''Apple Inc.'' vs ''Apple''). NULL for instruments without metadata entries. (Tier 2 -- SP_Dim_Instrument, etoro_Trade_InstrumentMetaData)';
ALTER TABLE main.bi_output.vg_trades ALTER COLUMN `InstrumentID` COMMENT 'FK to Trade.Instrument. Financial instrument being traded. (Tier 1 ג€” Trade.PositionTbl)';
ALTER TABLE main.bi_output.vg_trades ALTER COLUMN `InstrumentType` COMMENT 'Text label for InstrumentTypeID -- DWH-computed via CASE: 1=Currencies, 2=Commodities, 4=Indices, 5=Stocks, 6=ETF, 10=Crypto Currencies, else=Other. Use InstrumentTypeID for filtering; InstrumentType for display. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.bi_output.vg_trades ALTER COLUMN `InvestedAmountOpen` COMMENT 'Event type classifier. References `DWH_dbo.Dim_ActionType.ActionTypeID` ג€” JOIN for Name, Category, CategoryID. See Section 2.1 for full mapping. Key filter column ג€” drives which other columns are populated. (Tier 1 ג€” ETL-derived from CreditTypeID/source)';
ALTER TABLE main.bi_output.vg_trades ALTER COLUMN `IsFuture` COMMENT 'Derived flag indicating if the instrument is a futures contract: 1=futures, 0=not futures. Computed in SP as CASE WHEN InstrumentID IN (SELECT InstrumentID FROM InstrumentGroups WHERE GroupID=25) THEN 1 ELSE 0. NULL for ID=0 placeholder. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.bi_output.vg_trades ALTER COLUMN `IsProfessionalCustomer` COMMENT 'MiFID II client categorization (Retail/Professional/Eligible Counterparty). DEFAULT 0. Source: Ext_FSC_BackOffice_Customer.MifidCategorizationID (BO). FK to Dim_MifidCategorization. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.bi_output.vg_trades ALTER COLUMN `Leverage` COMMENT 'Leverage multiplier (1, 5, 10, etc.). Determines margin and settlement type. (Tier 1 ג€” Trade.PositionTbl)';
ALTER TABLE main.bi_output.vg_trades ALTER COLUMN `OpenTrades` COMMENT 'Event type classifier. References `DWH_dbo.Dim_ActionType.ActionTypeID` ג€” JOIN for Name, Category, CategoryID. See Section 2.1 for full mapping. Key filter column ג€” drives which other columns are populated. (Tier 1 ג€” ETL-derived from CreditTypeID/source)';
ALTER TABLE main.bi_output.vg_trades ALTER COLUMN `Real/CFD` COMMENT '1 = real asset, 0 = CFD asset. (Tier 5 ג€” Expert Review)';
ALTER TABLE main.bi_output.vg_trades ALTER COLUMN `RegistrationDate` COMMENT 'Account registration date (renamed from Registered). Default=getdate(). (Tier 1 ג€” Customer.CustomerStatic)';
ALTER TABLE main.bi_output.vg_trades ALTER COLUMN `TotalAmount` COMMENT 'Position size in currency. Must be >= 0. Stored in dollars (PositionOpen divides by 100 from cents). (Tier 1 ג€” Trade.PositionTbl)';
ALTER TABLE main.bi_output.vg_trades ALTER COLUMN `TotalTrades` COMMENT 'Event type classifier. References `DWH_dbo.Dim_ActionType.ActionTypeID` ג€” JOIN for Name, Category, CategoryID. See Section 2.1 for full mapping. Key filter column ג€” drives which other columns are populated. (Tier 1 ג€” ETL-derived from CreditTypeID/source)';

