ALTER TABLE main.bi_output_stg.vg_customer_common_statuses ALTER COLUMN `CountryID` COMMENT 'Customer''s registered country. DEFAULT 0. Source: Ext_FSC_Real_Customer_Customer.CountryID (CC). FK to Dim_Country. Key filter for valid customer segmentation (CountryID=250 excluded). (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.bi_output_stg.vg_customer_common_statuses ALTER COLUMN `FromDateID` COMMENT 'Start date of the customer snapshot range (YYYYMMDD integer). (Tier 2 ג€” view DDL)';
ALTER TABLE main.bi_output_stg.vg_customer_common_statuses ALTER COLUMN `IsCreditReportValidCB` COMMENT '1 if customer is eligible for CreditBureau credit report validation. ETL-computed. See ֲ§2.3. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.bi_output_stg.vg_customer_common_statuses ALTER COLUMN `IsValidCustomer` COMMENT '1 if the customer is a valid retail customer for analytics purposes. ETL-computed from PlayerLevelID, LabelID, CountryID. See ֲ§2.2. Approx 98% of current rows = 1. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.bi_output_stg.vg_customer_common_statuses ALTER COLUMN `MifidCategorization` COMMENT 'MiFID II client categorization (Retail/Professional/Eligible Counterparty). DEFAULT 0. Source: Ext_FSC_BackOffice_Customer.MifidCategorizationID (BO). FK to Dim_MifidCategorization. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.bi_output_stg.vg_customer_common_statuses ALTER COLUMN `MifidCategorizationID` COMMENT 'MiFID II client categorization (Retail/Professional/Eligible Counterparty). DEFAULT 0. Source: Ext_FSC_BackOffice_Customer.MifidCategorizationID (BO). FK to Dim_MifidCategorization. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.bi_output_stg.vg_customer_common_statuses ALTER COLUMN `MifidCategory` COMMENT 'MiFID II client categorization (Retail/Professional/Eligible Counterparty). DEFAULT 0. Source: Ext_FSC_BackOffice_Customer.MifidCategorizationID (BO). FK to Dim_MifidCategorization. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.bi_output_stg.vg_customer_common_statuses ALTER COLUMN `PlayerLevelID` COMMENT 'Account tier: 4=demo, other values=real tiers. DEFAULT 0. Source: Ext_FSC_Real_Customer_Customer.PlayerLevelID (CC). FK to Dim_PlayerLevel. Critical for IsValidCustomer (PlayerLevelID=4 excluded). (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.bi_output_stg.vg_customer_common_statuses ALTER COLUMN `RealCID` COMMENT 'Real (funded) customer ID. Hash distribution key. The primary customer identifier in the DWH ecosystem. FK to Dim_Customer (if exists). 46.4M distinct values. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.bi_output_stg.vg_customer_common_statuses ALTER COLUMN `RegulationID` COMMENT 'Customer''s assigned regulatory jurisdiction. DEFAULT 0. Sourced from Ext_FSC_BackOffice_RegulationChangeLog.ToRegulationID ג€” end-of-day change. See ֲ§2.4. FK to Dim_Regulation. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.bi_output_stg.vg_customer_common_statuses ALTER COLUMN `ToDateID` COMMENT 'End date of the customer snapshot range (YYYYMMDD integer). Active rows have ToDateID = YYYY1231. (Tier 2 ג€” view DDL)';
ALTER TABLE main.bi_output_stg.vg_customer_common_statuses ALTER COLUMN `VerificationLevelID` COMMENT 'KYC (Know Your Customer) verification level. DEFAULT -1. Source: Ext_FSC_BackOffice_Customer.VerificationLevelID (BO). FK to Dim_VerificationLevel. (Tier 2 - SP_Fact_SnapshotCustomer)';

