ALTER TABLE main.bi_output_stg.vg_customer_eoy2025_lifetimeinvested ALTER COLUMN `TotalLifetimeInvested` COMMENT 'Position size in currency. Must be >= 0. Stored in dollars (PositionOpen divides by 100 from cents). (Tier 1 ג€” Trade.PositionTbl)';

