ALTER TABLE main.bi_output_stg.vg_customer_eoy2025_lifetimepnl ALTER COLUMN `EOY2025_lifetimepnl` COMMENT 'Day-over-day change in total unrealized commission. Commission accrued but not yet realized (positions still open). (Tier 2 ג€” SP_Client_Balance_New)';

-- ----------------------------------------
-- main.bi_output_stg.vg_ddr_fact_revenue (27 columns)
-- ----------------------------------------
ALTER TABLE main.bi_output_stg.vg_ddr_fact_revenue ALTER COLUMN `ActionType` COMMENT 'Action or revenue stream label. `Dim_ActionType.Name` for commissions; literal string for others (''Rollover'', ''SDRT'', ''CashoutFeeExclRedeem'', etc.). (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output_stg.vg_ddr_fact_revenue ALTER COLUMN `ActionTypeID` COMMENT 'Trading action type. From `Function_Revenue_FullCommissions/Commissions.ActionTypeID` for trading fees; `ISNULL(...,-1)` ג€” sentinel -1 for non-trading metrics. Values: 1=Open, 39=Close. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output_stg.vg_ddr_fact_revenue ALTER COLUMN `Amount` COMMENT 'Revenue amount in USD. `SUM(fee_column)` aggregated per CID ֳ— Metric ֳ— flags group. Positive = revenue, negative possible for dividends paid out. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output_stg.vg_ddr_fact_revenue ALTER COLUMN `CountAsActiveTrade` COMMENT 'Active trade indicator. `CASE WHEN ActionTypeID IN (1,39) AND ISNULL(IsAirDrop,0) = 0 THEN 1 ELSE 0 END`; `ISNULL(...,0)`. Only 1 for non-airdrop commission rows. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output_stg.vg_ddr_fact_revenue ALTER COLUMN `CountTransactions` COMMENT 'Number of transactions/positions in the group. `COUNT(RealCID)` or `SUM(CountTransactions)`; `ISNULL(...,0)`. NULL/0 for ShareLending and Staking. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output_stg.vg_ddr_fact_revenue ALTER COLUMN `Date` COMMENT 'Calendar date. `@date` SP parameter for main INSERT; computed from DateID for Staking. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output_stg.vg_ddr_fact_revenue ALTER COLUMN `DateID` COMMENT 'Date key in YYYYMMDD format. DELETE/INSERT partition key. Direct from revenue functions (except Staking: lagged one month via `DATEADD(MONTH,1,...)`). (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output_stg.vg_ddr_fact_revenue ALTER COLUMN `IncludedInTotalRevenue` COMMENT 'Revenue inclusion flag. From `Dim_Revenue_Metrics.IncludedInTotalRevenue`. 1 = counts toward total revenue, 0 = excluded (Commission, Dividends, SDRT). (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output_stg.vg_ddr_fact_revenue ALTER COLUMN `InstrumentTypeID` COMMENT 'Instrument asset class. From revenue functions. `ISNULL(...,-1)` ג€” sentinel -1 for account-level fees (CashoutFee, ConversionFee, DormantFee, InterestFee). (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output_stg.vg_ddr_fact_revenue ALTER COLUMN `IsAirDrop` COMMENT 'AirDrop (free share) flag. From revenue functions; `ISNULL(...,-1)`. AirDrop positions excluded from active trade counts. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output_stg.vg_ddr_fact_revenue ALTER COLUMN `IsBuy` COMMENT 'Trade direction. `ISNULL(...,-1)`. 1=buy/long, 0=sell/short, -1=not applicable. Dividends: overridden to 1 if Amount>0, 0 if Amount<0. C2F: forced -1. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output_stg.vg_ddr_fact_revenue ALTER COLUMN `IsC2P` COMMENT 'Copy-to-Portfolio flag. `CASE WHEN V_C2P_Positions.PositionID IS NOT NULL THEN 1 ELSE 0 END`; `ISNULL(...,-1)`. NULL for non-position metrics. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output_stg.vg_ddr_fact_revenue ALTER COLUMN `IsClosedToIBAN` COMMENT 'Position closed to eMoney IBAN flag. Set via UPDATE JOIN to `External_*_closed_to_iban_parquet`; `ISNULL(...,-1)`. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output_stg.vg_ddr_fact_revenue ALTER COLUMN `IsCopy` COMMENT 'Copy-trade flag. `CASE WHEN MirrorID > 0 THEN 1 ELSE 0 END`; `ISNULL(...,-1)`. C2F forced to -1. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output_stg.vg_ddr_fact_revenue ALTER COLUMN `IsCopyFund` COMMENT 'Smart Portfolio flag. `CASE WHEN BI_DB_CopyFund_Positions.PositionID IS NOT NULL THEN 1 ELSE 0 END`; `ISNULL(...,-1)`. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output_stg.vg_ddr_fact_revenue ALTER COLUMN `IsFuture` COMMENT 'Futures contract flag. From functions or `Dim_Instrument.IsFuture` (AdminFee/SpotAdjust). `ISNULL(...,-1)`. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output_stg.vg_ddr_fact_revenue ALTER COLUMN `IsLeveraged` COMMENT 'Leverage flag. `CASE WHEN Leverage > 1 THEN 1 ELSE 0 END`; `ISNULL(...,-1)`. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output_stg.vg_ddr_fact_revenue ALTER COLUMN `IsMarginTrade` COMMENT 'Margin trade flag. From revenue functions; `ISNULL(...,-1)`. Forced 0 for SDRT and Options_PFOF. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output_stg.vg_ddr_fact_revenue ALTER COLUMN `IsOpenedFromIBAN` COMMENT 'Position opened from eMoney IBAN flag. Set via UPDATE JOIN to `External_*_opened_from_iban_parquet`; `ISNULL(...,-1)`. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output_stg.vg_ddr_fact_revenue ALTER COLUMN `IsRecurring` COMMENT 'Recurring investment position flag. Set via UPDATE JOIN to `External_bi_db_recurringinvestment_positions_parquet`; `ISNULL(...,-1)`. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output_stg.vg_ddr_fact_revenue ALTER COLUMN `IsSettled` COMMENT '1 = real asset, 0 = CFD asset. (Tier 5 ג€” Expert Review)';
ALTER TABLE main.bi_output_stg.vg_ddr_fact_revenue ALTER COLUMN `IsSQF` COMMENT 'Sustainable & Quality-Focused instrument flag. From functions or `Function_Instrument_Snapshot_Enriched`; `ISNULL(...,-1)`. NULL for Dividends/SDRT. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output_stg.vg_ddr_fact_revenue ALTER COLUMN `Metric` COMMENT 'Revenue stream identifier. 18 distinct values: ''FullCommission'', ''Commission'', ''RollOverFee'', ''Dividends'', ''SDRT'', ''TicketFee'', ''TicketFeeByPercent'', ''CashoutFeeExclRedeem'', ''ConversionFee'', ''DormantFee'', ''InterestFee'', ''TransferCoinFee'', ''AdminFee'', ''SpotPriceAdjustment'', ''ShareLending'', ''CryptoToFiatFee'', ''StakingLagOneMonth'', ''Options_PFOF''. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output_stg.vg_ddr_fact_revenue ALTER COLUMN `RealCID` COMMENT 'Customer identifier. Distribution key. From revenue functions (CID renamed to RealCID for some). (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output_stg.vg_ddr_fact_revenue ALTER COLUMN `RevenueMetricCategoryID` COMMENT 'Revenue category ID. From `Dim_Revenue_Metrics.RevenueMetricCategoryID`. Groups metrics into categories (4=Staking, 5=Options). (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output_stg.vg_ddr_fact_revenue ALTER COLUMN `RevenueMetricID` COMMENT 'Revenue metric dictionary ID. From `Dim_Revenue_Metrics.RevenueMetricID` via Metric text match. 12=Staking, 18=Options. Enables ID-based filtering. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.bi_output_stg.vg_ddr_fact_revenue ALTER COLUMN `UpdateDate` COMMENT 'ETL load timestamp. `GETDATE()` at SP execution time. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';

-- ----------------------------------------
-- main.bi_output_stg.vg_marketingacquisitionfunnel (7 columns)
-- ----------------------------------------
ALTER TABLE main.bi_output_stg.vg_marketingacquisitionfunnel ALTER COLUMN `Age_Tier` COMMENT 'Customer date of birth. Used in LinkedAccountHash1 for duplicate detection and in KYC age verification. (Tier 1 ג€” Customer.CustomerStatic)';
ALTER TABLE main.bi_output_stg.vg_marketingacquisitionfunnel ALTER COLUMN `DateTime_Reg` COMMENT 'Account registration date (renamed from Registered). Default=getdate(). (Tier 1 ג€” Customer.CustomerStatic)';
ALTER TABLE main.bi_output_stg.vg_marketingacquisitionfunnel ALTER COLUMN `Gender` COMMENT 'Gender: M, F, or U (Unknown). CHECK constraint CCST_GENDER enforces these three values only. Used in LinkedAccountHash1. (Tier 1 ג€” Customer.CustomerStatic)';
ALTER TABLE main.bi_output_stg.vg_marketingacquisitionfunnel ALTER COLUMN `Reg_EOM` COMMENT 'Account registration date (renamed from Registered). Default=getdate(). (Tier 1 ג€” Customer.CustomerStatic)';
ALTER TABLE main.bi_output_stg.vg_marketingacquisitionfunnel ALTER COLUMN `Reg_EOW` COMMENT 'Account registration date (renamed from Registered). Default=getdate(). (Tier 1 ג€” Customer.CustomerStatic)';
ALTER TABLE main.bi_output_stg.vg_marketingacquisitionfunnel ALTER COLUMN `Reg_SOM` COMMENT 'Account registration date (renamed from Registered). Default=getdate(). (Tier 1 ג€” Customer.CustomerStatic)';
ALTER TABLE main.bi_output_stg.vg_marketingacquisitionfunnel ALTER COLUMN `Reg_SOW` COMMENT 'Account registration date (renamed from Registered). Default=getdate(). (Tier 1 ג€” Customer.CustomerStatic)';

-- ----------------------------------------
-- main.bi_output_stg.vw_customer_action (11 columns)
-- ----------------------------------------
ALTER TABLE main.bi_output_stg.vw_customer_action ALTER COLUMN `ActionAmountUSD` COMMENT 'Position size in currency. Must be >= 0. Stored in dollars (PositionOpen divides by 100 from cents). (Tier 1 ג€” Trade.PositionTbl)';
ALTER TABLE main.bi_output_stg.vw_customer_action ALTER COLUMN `ActionType` COMMENT 'Event type classifier. References `DWH_dbo.Dim_ActionType.ActionTypeID` ג€” JOIN for Name, Category, CategoryID. See Section 2.1 for full mapping. Key filter column ג€” drives which other columns are populated. (Tier 1 ג€” ETL-derived from CreditTypeID/source)';
ALTER TABLE main.bi_output_stg.vw_customer_action ALTER COLUMN `CID` COMMENT 'Real-account Customer ID. HASH distribution key. References `Dim_Customer.RealCID`. Each customer has one real CID. (Tier 1 ג€” Customer.CustomerStatic)';
ALTER TABLE main.bi_output_stg.vw_customer_action ALTER COLUMN `GCID` COMMENT 'Global Customer ID ג€” the platform-wide unique customer identifier. References `Dim_Customer.GCID`. (Tier 1 ג€” Customer.CustomerStatic)';
ALTER TABLE main.bi_output_stg.vw_customer_action ALTER COLUMN `InstrumentDisplayName` COMMENT 'User-facing instrument display name from Trade.InstrumentMetaData. More descriptive than Name (e.g., ''Apple Inc.'' vs ''Apple''). NULL for instruments without metadata entries. (Tier 2 -- SP_Dim_Instrument, etoro_Trade_InstrumentMetaData)';
ALTER TABLE main.bi_output_stg.vw_customer_action ALTER COLUMN `InstrumentID` COMMENT 'FK to Trade.Instrument. Financial instrument being traded. (Tier 1 ג€” Trade.PositionTbl)';
ALTER TABLE main.bi_output_stg.vw_customer_action ALTER COLUMN `InstrumentType` COMMENT 'Text label for InstrumentTypeID -- DWH-computed via CASE: 1=Currencies, 2=Commodities, 4=Indices, 5=Stocks, 6=ETF, 10=Crypto Currencies, else=Other. Use InstrumentTypeID for filtering; InstrumentType for display. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.bi_output_stg.vw_customer_action ALTER COLUMN `IsPartialCloseChild` COMMENT '1=this position is the child (remainder) of a partial close event. (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
ALTER TABLE main.bi_output_stg.vw_customer_action ALTER COLUMN `Occurred` COMMENT 'UTC timestamp when the action occurred. For position opens: when position was opened. For logins: login time. For credits: when the credit was recorded. (Tier 1 ג€” source-dependent)';
ALTER TABLE main.bi_output_stg.vw_customer_action ALTER COLUMN `PositionID` COMMENT 'Primary key. Allocated by Internal.GetPositionID_Bigint. Unique per position. (Tier 1 ג€” Trade.PositionTbl)';
ALTER TABLE main.bi_output_stg.vw_customer_action ALTER COLUMN `PositionType` COMMENT '1 = real asset, 0 = CFD asset. (Tier 5 ג€” Expert Review)';

-- ----------------------------------------
-- main.data_rooms.vw_bi_output_dealing_newinstruments (46 columns)
-- ----------------------------------------
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `ADV_Last3Months` COMMENT 'Average Daily Trading Volume over the trailing 3 months (TTM), from Rankings StockInfo MetadataID=8557. In shares/units. NULL for non-stock instruments or instruments without Rankings coverage. Example: Apple ~48M shares/day. (Tier 2 -- SP_Dim_Instrument, Rankings_StockInfo)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `AllowBuy` COMMENT 'Flag indicating if long (buy) positions can currently be opened: 1=allowed, 0=disabled. Cast from bit. NULL for ID=0 placeholder. Instruments may be buy-disabled due to regulatory restrictions, risk management, or market conditions. (Tier 2 -- SP_Dim_Instrument, etoro.Trade.GetInstrument)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `AllowSell` COMMENT 'Flag indicating if short (sell) positions can currently be opened: 1=allowed, 0=disabled. Cast from bit. NULL for ID=0 placeholder. Many regulated markets prohibit short selling for retail clients. (Tier 2 -- SP_Dim_Instrument, etoro.Trade.GetInstrument)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `AssetClass` COMMENT 'Bloomberg-style asset class classification from Ext_Dim_Instrument_Classification_Static (e.g., Technology, Consumer Services, Finance). More granular than InstrumentType. NULL for non-stock instruments or instruments not in the classification static table. (Tier 2 -- SP_Dim_Instrument, post-load UPDATE)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `BonusCreditUsePercent` COMMENT 'Percentage of bonus credit that can be applied to trading this instrument, from Trade.ProviderToInstrument. Lower values restrict bonus usage for high-risk/volatile instruments. NULL for instruments without ProviderToInstrument mapping. (Tier 3 -- live data, etoro_Trade_ProviderToInstrument)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `BuyCurrency` COMMENT 'Text abbreviation of BuyCurrencyID -- denormalized from Dictionary.Currency.Abbreviation via SP JOIN. Example: EUR, AAPL, BTC. DWH-added for query convenience. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `BuyCurrencyID` COMMENT 'The buy-side asset of the instrument pair. FK to DWH_dbo.Dim_Currency(CurrencyID). For forex: the base currency. For stocks/ETFs/crypto: the asset''s own CurrencyID in Dim_Currency (BuyCurrencyID = InstrumentID for stocks). (Tier 1 -- upstream wiki, Trade.Instrument)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `CompanyInfo` COMMENT 'Free-text company description from Trade.InstrumentMetaData. May contain multi-sentence business descriptions of the company. NULL for non-company instruments (forex, commodities, indices). (Tier 3 -- live data, etoro_Trade_InstrumentMetaData)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `CUSIP` COMMENT 'Committee on Uniform Securities Identification Procedures number -- 9-character code for US/Canadian securities. Used for clearing, settlement, and regulatory reporting. NULL for non-US instruments and instruments without CUSIP. (Tier 2 -- SP_Dim_Instrument, etoro_Trade_InstrumentCusip)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `date_added_to_platform` COMMENT 'Flag indicating if long (buy) positions can currently be opened: 1=allowed, 0=disabled. Cast from bit. NULL for ID=0 placeholder. Instruments may be buy-disabled due to regulatory restrictions, risk management, or market conditions. (Tier 2 -- SP_Dim_Instrument, etoro.Trade.GetInstrument)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `DollarRatio` COMMENT 'Price scaling factor for USD normalization. Most instruments = 1. JPY pairs = 100 (because JPY is quoted at 100x the numeric value of other currencies). Used in P&L and conversion rate calculations across the platform. (Tier 1 -- upstream wiki, Trade.Instrument)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `DWHInstrumentID` COMMENT 'Always equal to InstrumentID -- redundant copy following the DWH DWH{X}ID pattern. Use InstrumentID for all JOINs. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `Exchange` COMMENT 'Stock exchange name from Trade.InstrumentMetaData (e.g., Nasdaq, NYSE, LSE). NULL for non-stock instruments. (Tier 3 -- live data, etoro_Trade_InstrumentMetaData)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `Industry` COMMENT 'Industry classification string from Trade.InstrumentMetaData. Text description (e.g., ''Internet'', ''Software''). Similar to but may differ from IndustryGroup (Bloomberg). NULL for non-stock instruments or instruments without metadata. (Tier 3 -- live data, etoro_Trade_InstrumentMetaData)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `IndustryGroup` COMMENT 'Bloomberg-style industry group within AssetClass (e.g., Computers, Internet, Banks). Sub-classification of AssetClass. NULL for non-stock instruments or instruments not in the classification table. (Tier 2 -- SP_Dim_Instrument, post-load UPDATE)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `InsertDate` COMMENT 'ETL load timestamp -- set to GETDATE() by SP_Dim_Instrument, same as UpdateDate. Both reflect the daily load time. Does NOT reflect production insertion date. NULL only for ID=0 placeholder. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `InstrumentDisplayName` COMMENT 'User-facing instrument display name from Trade.InstrumentMetaData. More descriptive than Name (e.g., ''Apple Inc.'' vs ''Apple''). NULL for instruments without metadata entries. (Tier 2 -- SP_Dim_Instrument, etoro_Trade_InstrumentMetaData)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `InstrumentID` COMMENT 'Primary key identifying the tradeable instrument pair. Allocated by Trade.InstrumentAdd during instrument creation. Ranges from 0 (system placeholder) to ~21 million IDs allocated. Referenced by virtually every trading fact table and the Dim_Currency / Dim_HistorySplitRatio dimension tables. (Tier 1 -- upstream wiki, Trade.Instrument)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `InstrumentType` COMMENT 'Text label for InstrumentTypeID -- DWH-computed via CASE: 1=Currencies, 2=Commodities, 4=Indices, 5=Stocks, 6=ETF, 10=Crypto Currencies, else=Other. Use InstrumentTypeID for filtering; InstrumentType for display. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `InstrumentTypeID` COMMENT 'Instrument type category: 1=Currencies (forex), 2=Commodities, 4=Indices, 5=Stocks, 6=ETF, 10=Crypto Currencies. Note TypeIDs 3, 7, 8, 9 are unused gaps. Distribution: Stocks 82%, ETF 8%, Crypto 4%, Commodities 3%, Indices 2%, Currencies 1%. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `IsFuture` COMMENT 'Derived flag indicating if the instrument is a futures contract: 1=futures, 0=not futures. Computed in SP as CASE WHEN InstrumentID IN (SELECT InstrumentID FROM InstrumentGroups WHERE GroupID=25) THEN 1 ELSE 0. NULL for ID=0 placeholder. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `ISINCode` COMMENT 'International Securities Identification Number -- 12-character alphanumeric code standardized by ISO 6166 (e.g., US0378331005 for Apple). NULL for forex, commodities, and instruments without ISIN. Country prefix + national code + check digit. (Tier 2 -- SP_Dim_Instrument, etoro_Trade_InstrumentMetaData)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `ISINCountryCode` COMMENT 'Country code prefix from the ISIN (first 2 characters). Indicates the country of registration (e.g., US, DE, GB). NULL when ISINCode is NULL. (Tier 2 -- SP_Dim_Instrument, etoro_Trade_InstrumentMetaData)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `IsMajor` COMMENT 'Text version of IsMajorID -- DWH CASE computed: IsMajorID=1->''Yes'', 0->''No''. Use for display. Affects spread calculations and regulatory leverage caps (ESMA allows higher leverage for major forex). (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `IsMajorID` COMMENT 'Integer representation of the production IsMajor flag (0 or 1). 1=major instrument (6,963 instruments -- all major forex pairs and many popular stocks). 0=non-major (8,743 instruments). Renamed from production IsMajor to distinguish from the text version. Use for filtering. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `MKTcap` COMMENT 'Market capitalization in USD from Rankings StockInfo (MetadataID=8735 for equities; fallback MetadataID=9315 CryptoMarketCap for crypto). NULL for forex, commodities, and indices. Example: Apple ~3.8T USD. (Tier 2 -- SP_Dim_Instrument, Rankings_StockInfo)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `Multiplier` COMMENT 'Futures contract size multiplier from Trade.FuturesMetaData. Determines how many units of the underlying asset one contract represents. NULL for non-futures instruments. (Tier 2 -- SP_Dim_Instrument, etoro_Trade_FuturesMetaData)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `Name` COMMENT 'Instrument name as defined in Trade.Instrument. For forex: pair notation (e.g., EUR/USD). For stocks: company name (e.g., Apple, Alphabet). For crypto: token name. This is the internal instrument name, not necessarily the display name shown to users (see InstrumentDisplayName). (Tier 3 -- live data, etoro.Trade.GetInstrument)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `PipDifferenceThreshold` COMMENT 'Maximum allowed pip difference threshold for price validation. If a new price deviates more than this threshold from the previous price, it may be flagged as suspicious. NULL for some instruments. (Tier 1 -- upstream wiki, Trade.Instrument)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `PlatformIndustry` COMMENT 'eToro platform industry classification from Rankings StockInfo MetadataID=8280. More granular than PlatformSector. NULL for non-equity instruments or instruments without Rankings coverage. (Tier 2 -- SP_Dim_Instrument, Rankings_StockInfo)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `PlatformSector` COMMENT 'eToro platform sector classification from Rankings StockInfo MetadataID=8436. May differ from Bloomberg AssetClass. NULL for non-equity instruments or instruments without Rankings coverage. (Tier 2 -- SP_Dim_Instrument, Rankings_StockInfo)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `Precision` COMMENT 'Decimal precision for price display and trading (number of decimal places), from Trade.ProviderToInstrument. Determines how many decimals are shown in the UI and used in calculations. NULL for instruments without ProviderToInstrument mapping. (Tier 3 -- live data, etoro_Trade_ProviderToInstrument)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `ProviderID` COMMENT 'Liquidity provider identifier from Trade.ProviderToInstrument. Identifies which external market maker or broker provides pricing/liquidity for this instrument. NULL for instruments without a provider mapping. (Tier 3 -- live data, etoro_Trade_ProviderToInstrument)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `ProviderMarginPerLot` COMMENT 'Initial margin requirement per lot in the provider''s terms, from Trade.FuturesInstrumentsInitialMarginByProviderMapping. Primarily relevant for futures instruments. NULL for non-futures or instruments without provider margin data. (Tier 3 -- live data, FuturesInstrumentsInitialMarginByProviderMapping)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `ReceivedOnPriceServer` COMMENT 'First timestamp when the instrument was observed on the price server (from Ext_Dim_Instrument_ReceivedOnPriceServerStatic). Set once and never updated (static history). NULL for instruments not yet priced or newly added instruments that have not yet appeared in price feeds. (Tier 2 -- SP_Dim_Instrument, post-load UPDATE)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `SellCurrency` COMMENT 'Text abbreviation of SellCurrencyID -- denormalized from Dictionary.Currency.Abbreviation. Example: USD, EUR, GBX (GBP pence). DWH-added for query convenience. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `SellCurrencyID` COMMENT 'The sell-side (denomination) currency. FK to DWH_dbo.Dim_Currency(CurrencyID). For forex: the quote currency (e.g., USD in EUR/USD). For stocks: the trading denomination currency (USD, EUR, GBX). Only 67 distinct values since many assets share the same denomination. (Tier 1 -- upstream wiki, Trade.Instrument)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `SettlementTime` COMMENT 'Daily or periodic settlement time for the instrument, from Trade.ProviderToInstrument, formatted as TIME via SP DATEPART conversion. Primarily relevant for futures and CFD instruments with defined settlement windows. NULL for instruments without settlement time defined. (Tier 3 -- live data, etoro_Trade_ProviderToInstrument)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `SharesOutStanding` COMMENT 'Total shares outstanding in units from Rankings StockInfo MetadataID=8444. Annual figure. NULL for non-equity instruments. Example: Apple ~14.7B shares. (Tier 2 -- SP_Dim_Instrument, Rankings_StockInfo)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `StatusID` COMMENT 'Hardcoded to 1 for all real rows by SP_Dim_Instrument. NULL only for ID=0 placeholder. Conveys no business information. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `Symbol` COMMENT 'Ticker symbol for the instrument (e.g., AAPL, EURUSD, BTCUSD). Used for display, search, and price feed identification. NULL for ID=0 placeholder and some instruments without formal ticker. (Tier 3 -- live data, etoro.Trade.GetInstrument)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `SymbolFull` COMMENT 'Full ticker symbol (may be longer than Symbol), from Trade.InstrumentMetaData. Used for data provider integrations that require fully qualified symbols. NULL for instruments without metadata. (Tier 3 -- live data, etoro_Trade_InstrumentMetaData)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `Tradable` COMMENT 'Flag indicating if the instrument is currently tradable: 1=tradable, 0=not tradable. CAST from production bit. NULL for ID=0 placeholder. An instrument may exist but be non-tradable due to regulatory, market, or operational reasons. (Tier 2 -- SP_Dim_Instrument, etoro.Trade.GetInstrument)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `TradeRange` COMMENT 'Allowed trade range in pips for pending orders. Determines how far from market price a limit/stop order can be placed. Set during instrument creation. (Tier 1 -- upstream wiki, Trade.Instrument)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `UpdateDate` COMMENT 'ETL load timestamp -- set to GETDATE() by SP_Dim_Instrument on each daily reload. Does NOT reflect production modification date. NULL only for ID=0 placeholder. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.data_rooms.vw_bi_output_dealing_newinstruments ALTER COLUMN `VisibleInternallyOnly` COMMENT 'Flag (0/1) indicating if the instrument is visible only to internal eToro users (not shown to retail customers). Cast from bit. Used for instruments under development, testing, or institutional-only. NULL for ID=0 placeholder. (Tier 3 -- live data, etoro.Trade.GetInstrument)';

-- ----------------------------------------
-- main.etoro_kpi.cfd_statusinfo_v (8 columns)
-- ----------------------------------------
ALTER TABLE main.etoro_kpi.cfd_statusinfo_v ALTER COLUMN `ApproprietnessScore_Status` COMMENT 'Appropriateness test outcome. From ComplianceStateDB Dictionary.RestrictionStatus.Name, filtered to RestrictionStatusReasonID=14. Distribution: "Failed" 75% (13.4M), "Passed" 24% (4.2M), blank 1%, "Borderline Pass" <0.1%. Note: column name contains typo ("Approprietness" vs "Appropriateness"). (Tier 2 ג€” SP_BI_DB_Scored_Appropriateness_Negative_Market, join-enriched)';
ALTER TABLE main.etoro_kpi.cfd_statusinfo_v ALTER COLUMN `BlockDate` COMMENT 'Date when CFD trading was blocked. From ComplianceStateDB UserTradingData. NULL if never blocked. Source depends on current status: if currently blocked ג†’ current.ReasonDate; if released ג†’ history.ReasonDate. (Tier 2 ג€” SP_BI_DB_Scored_Appropriateness_Negative_Market, ETL-computed)';
ALTER TABLE main.etoro_kpi.cfd_statusinfo_v ALTER COLUMN `BlockReasonDesc` COMMENT 'Block reason name. Decoded from ComplianceStateDB Dictionary.RestrictionStatusReason.Name. NULL if never blocked. (Tier 2 ג€” SP_BI_DB_Scored_Appropriateness_Negative_Market, join-enriched)';
ALTER TABLE main.etoro_kpi.cfd_statusinfo_v ALTER COLUMN `CFD_Status` COMMENT 'Derived CFD trading status. `CASE WHEN CFDRestrictionStatusID=1 THEN ''CFD_Blocked'' ELSE ''CFD_Allowed''`. 2-value enum: "CFD_Blocked" (20%, 3.6M), "CFD_Allowed" (80%, 14.3M). (Tier 2 ג€” SP_BI_DB_Scored_Appropriateness_Negative_Market, ETL-computed)';
ALTER TABLE main.etoro_kpi.cfd_statusinfo_v ALTER COLUMN `GCID` COMMENT 'Global Customer ID. Distribution key and clustered index column. Maps to Dim_Customer.GCID. (Tier 1 ג€” Account.Customer)';
ALTER TABLE main.etoro_kpi.cfd_statusinfo_v ALTER COLUMN `RealCID` COMMENT 'Customer Real account ID. Maps to Dim_Customer.RealCID. (Tier 1 ג€” etoro.Account.Customer.RealCID)';
ALTER TABLE main.etoro_kpi.cfd_statusinfo_v ALTER COLUMN `ReleaseDate` COMMENT 'Date when CFD block was released. Only populated when `CFDRestrictionStatusID = 2` (currently allowed after prior block). NULL if still blocked or never blocked. (Tier 2 ג€” SP_BI_DB_Scored_Appropriateness_Negative_Market, ETL-computed)';
ALTER TABLE main.etoro_kpi.cfd_statusinfo_v ALTER COLUMN `ReleaseReasonDesc` COMMENT 'Release reason name. Decoded from ComplianceStateDB Dictionary.RestrictionStatusReason.Name. NULL if not released. (Tier 2 ג€” SP_BI_DB_Scored_Appropriateness_Negative_Market, join-enriched)';

-- ----------------------------------------
-- main.etoro_kpi.customer_snapshot_v (22 columns)
-- ----------------------------------------
ALTER TABLE main.etoro_kpi.customer_snapshot_v ALTER COLUMN `AccountManagerID` COMMENT 'Assigned account manager (sales/retention). DEFAULT 0. Source: Ext_FSC_BackOffice_Customer.AccountManagerID (BO). FK to Dim_Manager. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.etoro_kpi.customer_snapshot_v ALTER COLUMN `AccountStatusID` COMMENT 'Account enabled/suspended status. DEFAULT 0. Distribution: 1=93.2% (Active), 0=6.1%, 2=0.9% (Inactive). Source: Ext_FSC_Real_Customer_Customer.AccountStatusID (CC). FK to Dim_AccountStatus. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.etoro_kpi.customer_snapshot_v ALTER COLUMN `AccountTypeID` COMMENT 'Account type (e.g., 7=Employee, 9=excluded type, 2=real account). DEFAULT 0. Source: Ext_FSC_BackOffice_Customer.AccountTypeID (BO). FK to Dim_AccountType. Used in IsCreditReportValidCB logic. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.etoro_kpi.customer_snapshot_v ALTER COLUMN `AffiliateID` COMMENT 'Affiliate (partner) ID under which the customer was acquired (renamed from SerialID). FK to BackOffice.Affiliate. NULL for direct/organic registrations. (Tier 1 ג€” Customer.CustomerStatic)';
ALTER TABLE main.etoro_kpi.customer_snapshot_v ALTER COLUMN `CitizenshipCountryID` COMMENT 'Country of citizenship (may differ from CountryID/residence). FK to Dictionary.Country. Added 2018 for enhanced KYC. (Tier 1 ג€” Customer.CustomerStatic)';
ALTER TABLE main.etoro_kpi.customer_snapshot_v ALTER COLUMN `CommunicationLanguageID` COMMENT 'Preferred communication language (may differ from interface language). DEFAULT 0. Source: Ext_FSC_Real_Customer_Customer.CommunicationLanguageID (CC). FK to Dim_Language. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.etoro_kpi.customer_snapshot_v ALTER COLUMN `CountryID` COMMENT 'Customer''s registered country. DEFAULT 0. Source: Ext_FSC_Real_Customer_Customer.CountryID (CC). FK to Dim_Country. Key filter for valid customer segmentation (CountryID=250 excluded). (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.etoro_kpi.customer_snapshot_v ALTER COLUMN `FirstDepositDate` COMMENT 'Date of first deposit. DEFAULT=''19000101''. Updated from CustomerFinanceDB FTD data with FTDRecoveryDate logic. (Tier 2 ג€” SP_Dim_Customer)';
ALTER TABLE main.etoro_kpi.customer_snapshot_v ALTER COLUMN `GCID` COMMENT 'Global Customer ID ג€” the cross-platform identifier linking RealCID to demo and external systems. Source: Ext_FSC_Real_Customer_Customer (primary), Ext_Dim_Customer_CustomerIdentification_DLT (fallback). (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.etoro_kpi.customer_snapshot_v ALTER COLUMN `GuruStatusID` COMMENT 'Popular Investor (Guru) program status. DEFAULT 0. Source: Ext_FSC_BackOffice_Customer.GuruStatusID (BO). FK to Dim_GuruStatus. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.etoro_kpi.customer_snapshot_v ALTER COLUMN `IsDepositor` COMMENT '1 if the customer has made at least one real-money deposit (FTD detected). Set when CID appears in Ext_FSC_Customer_FirstTimeDeposits. Never reverted to 0 once set. DEFAULT 0. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.etoro_kpi.customer_snapshot_v ALTER COLUMN `IsPI` COMMENT 'Popular Investor (Guru) program status. DEFAULT 0. Source: Ext_FSC_BackOffice_Customer.GuruStatusID (BO). FK to Dim_GuruStatus. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.etoro_kpi.customer_snapshot_v ALTER COLUMN `IsValidCustomer` COMMENT '1 if the customer is a valid retail customer for analytics purposes. ETL-computed from PlayerLevelID, LabelID, CountryID. See ֲ§2.2. Approx 98% of current rows = 1. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.etoro_kpi.customer_snapshot_v ALTER COLUMN `LanguageID` COMMENT 'Customer''s preferred interface language. DEFAULT 0. Source: Ext_FSC_Real_Customer_Customer.LanguageID (CC). FK to Dim_Language. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.etoro_kpi.customer_snapshot_v ALTER COLUMN `PlayerLevelID` COMMENT 'Account tier: 4=demo, other values=real tiers. DEFAULT 0. Source: Ext_FSC_Real_Customer_Customer.PlayerLevelID (CC). FK to Dim_PlayerLevel. Critical for IsValidCustomer (PlayerLevelID=4 excluded). (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.etoro_kpi.customer_snapshot_v ALTER COLUMN `PlayerStatusID` COMMENT 'Customer lifecycle status (e.g., Active, Blocked, Pending). DEFAULT 0. Source: Ext_FSC_Real_Customer_Customer.PlayerStatusID (CC). FK to Dim_PlayerStatus. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.etoro_kpi.customer_snapshot_v ALTER COLUMN `PlayerStatusReasonID` COMMENT 'Reason code for the current PlayerStatusID (e.g., why account was blocked). DEFAULT 0. Source: Ext_FSC_Real_Customer_Customer.PlayerStatusReasonID (CC). FK to Dim_PlayerStatusReasons. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.etoro_kpi.customer_snapshot_v ALTER COLUMN `PlayerStatusSubReasonID` COMMENT 'Sub-reason code for PlayerStatus (more granular than PlayerStatusReasonID). DEFAULT 0. Source: Ext_FSC_Real_Customer_Customer.PlayerStatusSubReasonID (CC). FK to Dim_PlayerStatusSubReasons. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.etoro_kpi.customer_snapshot_v ALTER COLUMN `RealCID` COMMENT 'Real (funded) customer ID. Hash distribution key. The primary customer identifier in the DWH ecosystem. FK to Dim_Customer (if exists). 46.4M distinct values. (Tier 2 - SP_Fact_SnapshotCustomer)';
