-- ----------------------------------------
-- main.etoro_kpi.positions_for_compliance_v (18 columns)
-- ----------------------------------------
ALTER TABLE main.etoro_kpi.positions_for_compliance_v ALTER COLUMN `buycurrency` COMMENT 'Text abbreviation of BuyCurrencyID -- denormalized from Dictionary.Currency.Abbreviation via SP JOIN. Example: EUR, AAPL, BTC. DWH-added for query convenience. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.etoro_kpi.positions_for_compliance_v ALTER COLUMN `buycurrencyid` COMMENT 'The buy-side asset of the instrument pair. FK to DWH_dbo.Dim_Currency(CurrencyID). For forex: the base currency. For stocks/ETFs/crypto: the asset''s own CurrencyID in Dim_Currency (BuyCurrencyID = InstrumentID for stocks). (Tier 1 -- upstream wiki, Trade.Instrument)';
ALTER TABLE main.etoro_kpi.positions_for_compliance_v ALTER COLUMN `cusip` COMMENT 'Committee on Uniform Securities Identification Procedures number -- 9-character code for US/Canadian securities. Used for clearing, settlement, and regulatory reporting. NULL for non-US instruments and instruments without CUSIP. (Tier 2 -- SP_Dim_Instrument, etoro_Trade_InstrumentCusip)';
ALTER TABLE main.etoro_kpi.positions_for_compliance_v ALTER COLUMN `exchange` COMMENT 'Stock exchange name from Trade.InstrumentMetaData (e.g., Nasdaq, NYSE, LSE). NULL for non-stock instruments. (Tier 3 -- live data, etoro_Trade_InstrumentMetaData)';
ALTER TABLE main.etoro_kpi.positions_for_compliance_v ALTER COLUMN `industry` COMMENT 'Industry classification string from Trade.InstrumentMetaData. Text description (e.g., ''Internet'', ''Software''). Similar to but may differ from IndustryGroup (Bloomberg). NULL for non-stock instruments or instruments without metadata. (Tier 3 -- live data, etoro_Trade_InstrumentMetaData)';
ALTER TABLE main.etoro_kpi.positions_for_compliance_v ALTER COLUMN `Instrument` COMMENT 'Instrument name as defined in Trade.Instrument. For forex: pair notation (e.g., EUR/USD). For stocks: company name (e.g., Apple, Alphabet). For crypto: token name. This is the internal instrument name, not necessarily the display name shown to users (see InstrumentDisplayName). (Tier 3 -- live data, etoro.Trade.GetInstrument)';
ALTER TABLE main.etoro_kpi.positions_for_compliance_v ALTER COLUMN `instrumentdisplayname` COMMENT 'User-facing instrument display name from Trade.InstrumentMetaData. More descriptive than Name (e.g., ''Apple Inc.'' vs ''Apple''). NULL for instruments without metadata entries. (Tier 2 -- SP_Dim_Instrument, etoro_Trade_InstrumentMetaData)';
ALTER TABLE main.etoro_kpi.positions_for_compliance_v ALTER COLUMN `instrumenttype` COMMENT 'Text label for InstrumentTypeID -- DWH-computed via CASE: 1=Currencies, 2=Commodities, 4=Indices, 5=Stocks, 6=ETF, 10=Crypto Currencies, else=Other. Use InstrumentTypeID for filtering; InstrumentType for display. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.etoro_kpi.positions_for_compliance_v ALTER COLUMN `instrumenttypeid` COMMENT 'Instrument type category: 1=Currencies (forex), 2=Commodities, 4=Indices, 5=Stocks, 6=ETF, 10=Crypto Currencies. Note TypeIDs 3, 7, 8, 9 are unused gaps. Distribution: Stocks 82%, ETF 8%, Crypto 4%, Commodities 3%, Indices 2%, Currencies 1%. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.etoro_kpi.positions_for_compliance_v ALTER COLUMN `isfuture` COMMENT 'Derived flag indicating if the instrument is a futures contract: 1=futures, 0=not futures. Computed in SP as CASE WHEN InstrumentID IN (SELECT InstrumentID FROM InstrumentGroups WHERE GroupID=25) THEN 1 ELSE 0. NULL for ID=0 placeholder. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.etoro_kpi.positions_for_compliance_v ALTER COLUMN `isincode` COMMENT 'International Securities Identification Number -- 12-character alphanumeric code standardized by ISO 6166 (e.g., US0378331005 for Apple). NULL for forex, commodities, and instruments without ISIN. Country prefix + national code + check digit. (Tier 2 -- SP_Dim_Instrument, etoro_Trade_InstrumentMetaData)';
ALTER TABLE main.etoro_kpi.positions_for_compliance_v ALTER COLUMN `isincountrycode` COMMENT 'Country code prefix from the ISIN (first 2 characters). Indicates the country of registration (e.g., US, DE, GB). NULL when ISINCode is NULL. (Tier 2 -- SP_Dim_Instrument, etoro_Trade_InstrumentMetaData)';
ALTER TABLE main.etoro_kpi.positions_for_compliance_v ALTER COLUMN `ismajor` COMMENT 'Text version of IsMajorID -- DWH CASE computed: IsMajorID=1->''Yes'', 0->''No''. Use for display. Affects spread calculations and regulatory leverage caps (ESMA allows higher leverage for major forex). (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.etoro_kpi.positions_for_compliance_v ALTER COLUMN `sellcurrency` COMMENT 'Text abbreviation of SellCurrencyID -- denormalized from Dictionary.Currency.Abbreviation. Example: USD, EUR, GBX (GBP pence). DWH-added for query convenience. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.etoro_kpi.positions_for_compliance_v ALTER COLUMN `sellcurrencyid` COMMENT 'The sell-side (denomination) currency. FK to DWH_dbo.Dim_Currency(CurrencyID). For forex: the quote currency (e.g., USD in EUR/USD). For stocks: the trading denomination currency (USD, EUR, GBX). Only 67 distinct values since many assets share the same denomination. (Tier 1 -- upstream wiki, Trade.Instrument)';
ALTER TABLE main.etoro_kpi.positions_for_compliance_v ALTER COLUMN `symbol` COMMENT 'Ticker symbol for the instrument (e.g., AAPL, EURUSD, BTCUSD). Used for display, search, and price feed identification. NULL for ID=0 placeholder and some instruments without formal ticker. (Tier 3 -- live data, etoro.Trade.GetInstrument)';
ALTER TABLE main.etoro_kpi.positions_for_compliance_v ALTER COLUMN `symbolfull` COMMENT 'Full ticker symbol (may be longer than Symbol), from Trade.InstrumentMetaData. Used for data provider integrations that require fully qualified symbols. NULL for instruments without metadata. (Tier 3 -- live data, etoro_Trade_InstrumentMetaData)';
ALTER TABLE main.etoro_kpi.positions_for_compliance_v ALTER COLUMN `tradable` COMMENT 'Flag indicating if the instrument is currently tradable: 1=tradable, 0=not tradable. CAST from production bit. NULL for ID=0 placeholder. An instrument may exist but be non-tradable due to regulatory, market, or operational reasons. (Tier 2 -- SP_Dim_Instrument, etoro.Trade.GetInstrument)';

