ALTER TABLE main.etoro_kpi.vg_customer_daily_snapshot ALTER COLUMN `AccountManagerID` COMMENT 'Assigned account manager (sales/retention). DEFAULT 0. Source: Ext_FSC_BackOffice_Customer.AccountManagerID (BO). FK to Dim_Manager. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.etoro_kpi.vg_customer_daily_snapshot ALTER COLUMN `AccountStatusID` COMMENT 'Account enabled/suspended status. DEFAULT 0. Distribution: 1=93.2% (Active), 0=6.1%, 2=0.9% (Inactive). Source: Ext_FSC_Real_Customer_Customer.AccountStatusID (CC). FK to Dim_AccountStatus. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.etoro_kpi.vg_customer_daily_snapshot ALTER COLUMN `AccountTypeID` COMMENT 'Account type (e.g., 7=Employee, 9=excluded type, 2=real account). DEFAULT 0. Source: Ext_FSC_BackOffice_Customer.AccountTypeID (BO). FK to Dim_AccountType. Used in IsCreditReportValidCB logic. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.etoro_kpi.vg_customer_daily_snapshot ALTER COLUMN `ActiveTraded` COMMENT 'Actively traded on this date. From Function_Population_Active_Traders. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi.vg_customer_daily_snapshot ALTER COLUMN `BalanceOnlyAccount` COMMENT 'Balance-only account (has balance, no trading/portfolio). From Function_Population_Balance_Only_Accounts. Returns equity value, not 0/1. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi.vg_customer_daily_snapshot ALTER COLUMN `CommunicationLanguageID` COMMENT 'Preferred communication language (may differ from interface language). DEFAULT 0. Source: Ext_FSC_Real_Customer_Customer.CommunicationLanguageID (CC). FK to Dim_Language. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.etoro_kpi.vg_customer_daily_snapshot ALTER COLUMN `CountryID` COMMENT 'Customer''s registered country. DEFAULT 0. Source: Ext_FSC_Real_Customer_Customer.CountryID (CC). FK to Dim_Country. Key filter for valid customer segmentation (CountryID=250 excluded). (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.etoro_kpi.vg_customer_daily_snapshot ALTER COLUMN `GlobalCashedOut` COMMENT 'Withdrew today on any platform (excluding internal transfers). (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi.vg_customer_daily_snapshot ALTER COLUMN `GlobalDeposited` COMMENT 'Deposited today on any platform (excluding internal transfers). ISNULL(0). (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi.vg_customer_daily_snapshot ALTER COLUMN `GlobalRedeposited` COMMENT 'Redeposited today (not FTD, not internal). (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi.vg_customer_daily_snapshot ALTER COLUMN `GuruStatusID` COMMENT 'Popular Investor (Guru) program status. DEFAULT 0. Source: Ext_FSC_BackOffice_Customer.GuruStatusID (BO). FK to Dim_GuruStatus. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.etoro_kpi.vg_customer_daily_snapshot ALTER COLUMN `IsCreditReportValidCB` COMMENT '1 if customer is eligible for CreditBureau credit report validation. ETL-computed. See ֲ§2.3. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.etoro_kpi.vg_customer_daily_snapshot ALTER COLUMN `IsFunded` COMMENT 'Currently funded. 1 when customer appears in Function_Population_Funded. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi.vg_customer_daily_snapshot ALTER COLUMN `IsPI` COMMENT 'Popular Investor (Guru) program status. DEFAULT 0. Source: Ext_FSC_BackOffice_Customer.GuruStatusID (BO). FK to Dim_GuruStatus. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.etoro_kpi.vg_customer_daily_snapshot ALTER COLUMN `IsValidCustomer` COMMENT '1 if the customer is a valid retail customer for analytics purposes. ETL-computed from PlayerLevelID, LabelID, CountryID. See ֲ§2.2. Approx 98% of current rows = 1. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.etoro_kpi.vg_customer_daily_snapshot ALTER COLUMN `LanguageID` COMMENT 'Customer''s preferred interface language. DEFAULT 0. Source: Ext_FSC_Real_Customer_Customer.LanguageID (CC). FK to Dim_Language. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.etoro_kpi.vg_customer_daily_snapshot ALTER COLUMN `MifidCategorizationID` COMMENT 'MiFID II client categorization (Retail/Professional/Eligible Counterparty). DEFAULT 0. Source: Ext_FSC_BackOffice_Customer.MifidCategorizationID (BO). FK to Dim_MifidCategorization. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.etoro_kpi.vg_customer_daily_snapshot ALTER COLUMN `PlayerLevelID` COMMENT 'Account tier: 4=demo, other values=real tiers. DEFAULT 0. Source: Ext_FSC_Real_Customer_Customer.PlayerLevelID (CC). FK to Dim_PlayerLevel. Critical for IsValidCustomer (PlayerLevelID=4 excluded). (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.etoro_kpi.vg_customer_daily_snapshot ALTER COLUMN `PlayerStatusID` COMMENT 'Customer lifecycle status (e.g., Active, Blocked, Pending). DEFAULT 0. Source: Ext_FSC_Real_Customer_Customer.PlayerStatusID (CC). FK to Dim_PlayerStatus. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.etoro_kpi.vg_customer_daily_snapshot ALTER COLUMN `PlayerStatusReasonID` COMMENT 'Reason code for the current PlayerStatusID (e.g., why account was blocked). DEFAULT 0. Source: Ext_FSC_Real_Customer_Customer.PlayerStatusReasonID (CC). FK to Dim_PlayerStatusReasons. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.etoro_kpi.vg_customer_daily_snapshot ALTER COLUMN `PlayerStatusSubReasonID` COMMENT 'Sub-reason code for PlayerStatus (more granular than PlayerStatusReasonID). DEFAULT 0. Source: Ext_FSC_Real_Customer_Customer.PlayerStatusSubReasonID (CC). FK to Dim_PlayerStatusSubReasons. (Tier 2 - SP_Fact_SnapshotCustomer)';
ALTER TABLE main.etoro_kpi.vg_customer_daily_snapshot ALTER COLUMN `Portfolio_Only` COMMENT 'Portfolio-only (has portfolio, not actively trading). From Function_Population_Portfolio_Only. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi.vg_customer_daily_snapshot ALTER COLUMN `RealCID` COMMENT 'Real customer ID. Population from 5-layer waterfall (TP ג†’ IBAN ג†’ Options ג†’ OptionsMIMO ג†’ MoneyFarm). HASH distribution key. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi.vg_customer_daily_snapshot ALTER COLUMN `Redeemed` COMMENT 'Billing redeem withdrawal today. From MIMO IsRedeem flag. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi.vg_customer_daily_snapshot ALTER COLUMN `RegulationID` COMMENT 'Customer''s assigned regulatory jurisdiction. DEFAULT 0. Sourced from Ext_FSC_BackOffice_RegulationChangeLog.ToRegulationID ג€” end-of-day change. See ֲ§2.4. FK to Dim_Regulation. (Tier 2 - SP_Fact_SnapshotCustomer)';

