ALTER TABLE main.etoro_kpi.vg_customer_monthly_snapshot ALTER COLUMN `AccountStatusID` COMMENT 'Account enabled/suspended status. DEFAULT 0. Distribution: 1=93.2% (Active), 0=6.1%, 2=0.9% (Inactive). Source: Ext_FSC_Real_Customer_Customer.AccountStatusID (CC). FK to Dim_AccountStatus. (Tier 2 - SP_Fact_SnapshotCustomer)';
