ALTER TABLE main.etoro_kpi.vg_customer_monthly_snapshot ALTER COLUMN `CommunicationLanguageID` COMMENT 'Preferred communication language (may differ from interface language). DEFAULT 0. Source: Ext_FSC_Real_Customer_Customer.CommunicationLanguageID (CC). FK to Dim_Language. (Tier 2 - SP_Fact_SnapshotCustomer)';
