ALTER TABLE main.etoro_kpi.vg_daily_commission_report ALTER COLUMN `instrumentdisplayname` COMMENT 'User-facing instrument display name from Trade.InstrumentMetaData. More descriptive than Name (e.g., ''Apple Inc.'' vs ''Apple''). NULL for instruments without metadata entries. (Tier 2 -- SP_Dim_Instrument, etoro_Trade_InstrumentMetaData)';
ALTER TABLE main.etoro_kpi.vg_daily_commission_report ALTER COLUMN `IsFuture` COMMENT 'Derived flag indicating if the instrument is a futures contract: 1=futures, 0=not futures. Computed in SP as CASE WHEN InstrumentID IN (SELECT InstrumentID FROM InstrumentGroups WHERE GroupID=25) THEN 1 ELSE 0. NULL for ID=0 placeholder. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.etoro_kpi.vg_daily_commission_report ALTER COLUMN `IsICC` COMMENT 'Derived flag indicating if the instrument is a futures contract: 1=futures, 0=not futures. Computed in SP as CASE WHEN InstrumentID IN (SELECT InstrumentID FROM InstrumentGroups WHERE GroupID=25) THEN 1 ELSE 0. NULL for ID=0 placeholder. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.etoro_kpi.vg_daily_commission_report ALTER COLUMN `symbol` COMMENT 'Ticker symbol for the instrument (e.g., AAPL, EURUSD, BTCUSD). Used for display, search, and price feed identification. NULL for ID=0 placeholder and some instruments without formal ticker. (Tier 3 -- live data, etoro.Trade.GetInstrument)';

-- ----------------------------------------
-- main.etoro_kpi.vg_ddr_revenue (28 columns)
-- ----------------------------------------
ALTER TABLE main.etoro_kpi.vg_ddr_revenue ALTER COLUMN `ActionType` COMMENT 'Action or revenue stream label. `Dim_ActionType.Name` for commissions; literal string for others (''Rollover'', ''SDRT'', ''CashoutFeeExclRedeem'', etc.). (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_ddr_revenue ALTER COLUMN `ActionTypeID` COMMENT 'Trading action type. From `Function_Revenue_FullCommissions/Commissions.ActionTypeID` for trading fees; `ISNULL(...,-1)` ג€” sentinel -1 for non-trading metrics. Values: 1=Open, 39=Close. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_ddr_revenue ALTER COLUMN `Amount` COMMENT 'Revenue amount in USD. `SUM(fee_column)` aggregated per CID ֳ— Metric ֳ— flags group. Positive = revenue, negative possible for dividends paid out. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_ddr_revenue ALTER COLUMN `CountAsActiveTrade` COMMENT 'Active trade indicator. `CASE WHEN ActionTypeID IN (1,39) AND ISNULL(IsAirDrop,0) = 0 THEN 1 ELSE 0 END`; `ISNULL(...,0)`. Only 1 for non-airdrop commission rows. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_ddr_revenue ALTER COLUMN `CountTransactions` COMMENT 'Number of transactions/positions in the group. `COUNT(RealCID)` or `SUM(CountTransactions)`; `ISNULL(...,0)`. NULL/0 for ShareLending and Staking. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_ddr_revenue ALTER COLUMN `Date` COMMENT 'Calendar date. `@date` SP parameter for main INSERT; computed from DateID for Staking. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_ddr_revenue ALTER COLUMN `DateID` COMMENT 'Date key in YYYYMMDD format. DELETE/INSERT partition key. Direct from revenue functions (except Staking: lagged one month via `DATEADD(MONTH,1,...)`). (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_ddr_revenue ALTER COLUMN `IncludedInTotalRevenue` COMMENT 'Revenue inclusion flag. From `Dim_Revenue_Metrics.IncludedInTotalRevenue`. 1 = counts toward total revenue, 0 = excluded (Commission, Dividends, SDRT). (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_ddr_revenue ALTER COLUMN `InstrumentTypeID` COMMENT 'Instrument asset class. From revenue functions. `ISNULL(...,-1)` ג€” sentinel -1 for account-level fees (CashoutFee, ConversionFee, DormantFee, InterestFee). (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_ddr_revenue ALTER COLUMN `IsAirDrop` COMMENT 'AirDrop (free share) flag. From revenue functions; `ISNULL(...,-1)`. AirDrop positions excluded from active trade counts. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_ddr_revenue ALTER COLUMN `IsBuy` COMMENT 'Trade direction. `ISNULL(...,-1)`. 1=buy/long, 0=sell/short, -1=not applicable. Dividends: overridden to 1 if Amount>0, 0 if Amount<0. C2F: forced -1. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_ddr_revenue ALTER COLUMN `IsC2P` COMMENT 'Copy-to-Portfolio flag. `CASE WHEN V_C2P_Positions.PositionID IS NOT NULL THEN 1 ELSE 0 END`; `ISNULL(...,-1)`. NULL for non-position metrics. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_ddr_revenue ALTER COLUMN `IsClosedToIBAN` COMMENT 'Position closed to eMoney IBAN flag. Set via UPDATE JOIN to `External_*_closed_to_iban_parquet`; `ISNULL(...,-1)`. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_ddr_revenue ALTER COLUMN `IsCopy` COMMENT 'Copy-trade flag. `CASE WHEN MirrorID > 0 THEN 1 ELSE 0 END`; `ISNULL(...,-1)`. C2F forced to -1. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_ddr_revenue ALTER COLUMN `IsCopyFund` COMMENT 'Smart Portfolio flag. `CASE WHEN BI_DB_CopyFund_Positions.PositionID IS NOT NULL THEN 1 ELSE 0 END`; `ISNULL(...,-1)`. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_ddr_revenue ALTER COLUMN `IsFuture` COMMENT 'Futures contract flag. From functions or `Dim_Instrument.IsFuture` (AdminFee/SpotAdjust). `ISNULL(...,-1)`. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_ddr_revenue ALTER COLUMN `IsICC` COMMENT 'Futures contract flag. From functions or `Dim_Instrument.IsFuture` (AdminFee/SpotAdjust). `ISNULL(...,-1)`. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_ddr_revenue ALTER COLUMN `IsLeveraged` COMMENT 'Leverage flag. `CASE WHEN Leverage > 1 THEN 1 ELSE 0 END`; `ISNULL(...,-1)`. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_ddr_revenue ALTER COLUMN `IsMarginTrade` COMMENT 'Margin trade flag. From revenue functions; `ISNULL(...,-1)`. Forced 0 for SDRT and Options_PFOF. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_ddr_revenue ALTER COLUMN `IsOpenedFromIBAN` COMMENT 'Position opened from eMoney IBAN flag. Set via UPDATE JOIN to `External_*_opened_from_iban_parquet`; `ISNULL(...,-1)`. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_ddr_revenue ALTER COLUMN `IsRecurring` COMMENT 'Recurring investment position flag. Set via UPDATE JOIN to `External_bi_db_recurringinvestment_positions_parquet`; `ISNULL(...,-1)`. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_ddr_revenue ALTER COLUMN `IsSettled` COMMENT '1 = real asset, 0 = CFD asset. (Tier 5 ג€” Expert Review)';
ALTER TABLE main.etoro_kpi.vg_ddr_revenue ALTER COLUMN `IsSQF` COMMENT 'Sustainable & Quality-Focused instrument flag. From functions or `Function_Instrument_Snapshot_Enriched`; `ISNULL(...,-1)`. NULL for Dividends/SDRT. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_ddr_revenue ALTER COLUMN `Metric` COMMENT 'Revenue stream identifier. 18 distinct values: ''FullCommission'', ''Commission'', ''RollOverFee'', ''Dividends'', ''SDRT'', ''TicketFee'', ''TicketFeeByPercent'', ''CashoutFeeExclRedeem'', ''ConversionFee'', ''DormantFee'', ''InterestFee'', ''TransferCoinFee'', ''AdminFee'', ''SpotPriceAdjustment'', ''ShareLending'', ''CryptoToFiatFee'', ''StakingLagOneMonth'', ''Options_PFOF''. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_ddr_revenue ALTER COLUMN `RealCID` COMMENT 'Customer identifier. Distribution key. From revenue functions (CID renamed to RealCID for some). (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_ddr_revenue ALTER COLUMN `RevenueMetricCategoryID` COMMENT 'Revenue category ID. From `Dim_Revenue_Metrics.RevenueMetricCategoryID`. Groups metrics into categories (4=Staking, 5=Options). (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_ddr_revenue ALTER COLUMN `RevenueMetricID` COMMENT 'Revenue metric dictionary ID. From `Dim_Revenue_Metrics.RevenueMetricID` via Metric text match. 12=Staking, 18=Options. Enables ID-based filtering. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_ddr_revenue ALTER COLUMN `UpdateDate` COMMENT 'ETL load timestamp. `GETDATE()` at SP execution time. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';

