ALTER TABLE main.etoro_kpi.vg_dealing_clicks_openclose_breakdown ALTER COLUMN `Multiplier` COMMENT 'Futures contract size multiplier from Trade.FuturesMetaData. Determines how many units of the underlying asset one contract represents. NULL for non-futures instruments. (Tier 2 -- SP_Dim_Instrument, etoro_Trade_FuturesMetaData)';

