ALTER TABLE main.etoro_kpi.vg_management_kpis ALTER COLUMN `Active_Trader_Crypto` COMMENT 'Active trade indicator. `CASE WHEN ActionTypeID IN (1,39) AND ISNULL(IsAirDrop,0) = 0 THEN 1 ELSE 0 END`; `ISNULL(...,0)`. Only 1 for non-airdrop commission rows. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_management_kpis ALTER COLUMN `Active_Trader_Futures` COMMENT 'Active trade indicator. `CASE WHEN ActionTypeID IN (1,39) AND ISNULL(IsAirDrop,0) = 0 THEN 1 ELSE 0 END`; `ISNULL(...,0)`. Only 1 for non-airdrop commission rows. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_management_kpis ALTER COLUMN `Active_Trader_ICC` COMMENT 'Instrument asset class. From revenue functions. `ISNULL(...,-1)` ג€” sentinel -1 for account-level fees (CashoutFee, ConversionFee, DormantFee, InterestFee). (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_management_kpis ALTER COLUMN `Active_Trader_Stocks` COMMENT 'Futures contract flag. From functions or `Dim_Instrument.IsFuture` (AdminFee/SpotAdjust). `ISNULL(...,-1)`. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_management_kpis ALTER COLUMN `Cashout_Amount` COMMENT 'Transaction direction. `''Deposit''` for money in, `''Withdraw''` for money out. Passthrough from sub-platform tables. (Tier 2 ג€” SP_DDR_Fact_Fact_MIMO_AllPlatforms)';
ALTER TABLE main.etoro_kpi.vg_management_kpis ALTER COLUMN `Crypto_Trading_Revenue` COMMENT 'Instrument asset class. From revenue functions. `ISNULL(...,-1)` ג€” sentinel -1 for account-level fees (CashoutFee, ConversionFee, DormantFee, InterestFee). (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_management_kpis ALTER COLUMN `Date` COMMENT 'Calendar date. `@date` SP parameter for main INSERT; computed from DateID for Staking. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_management_kpis ALTER COLUMN `DateID` COMMENT 'Date key in YYYYMMDD format. DELETE/INSERT partition key. Direct from revenue functions (except Staking: lagged one month via `DATEADD(MONTH,1,...)`). (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_management_kpis ALTER COLUMN `Deposit_Amount` COMMENT 'Internal fund transfer flag. `ISNULL(f.IsInternalTransfer, 0)`. 1 = transfer between platforms (TPג†”eMoney), not an external deposit/withdrawal. (Tier 2 ג€” SP_DDR_Fact_Fact_MIMO_AllPlatforms)';
ALTER TABLE main.etoro_kpi.vg_management_kpis ALTER COLUMN `FTD_Copy_CurrentYear` COMMENT 'First trading action type (e.g., ''Crypto'', ''Forex'', ''Stocks''). From Function_Population_First_Trading_Action. ''NoAction'' if none or future. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi.vg_management_kpis ALTER COLUMN `FTD_Crypto_CurrentYear` COMMENT 'Global first-time deposit datetime ג€” earliest across all platforms. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi.vg_management_kpis ALTER COLUMN `FTD_CurrentYear` COMMENT 'Global first-time deposit datetime ג€” earliest across all platforms. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi.vg_management_kpis ALTER COLUMN `FTD_ICC_CurrentYear` COMMENT 'Real customer ID. Population from 5-layer waterfall (TP ג†’ IBAN ג†’ Options ג†’ OptionsMIMO ג†’ MoneyFarm). HASH distribution key. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi.vg_management_kpis ALTER COLUMN `FTD_Stocks_CurrentYear` COMMENT 'First trading action type (e.g., ''Crypto'', ''Forex'', ''Stocks''). From Function_Population_First_Trading_Action. ''NoAction'' if none or future. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi.vg_management_kpis ALTER COLUMN `FundedAccounts` COMMENT 'Currently funded. 1 when customer appears in Function_Population_Funded. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi.vg_management_kpis ALTER COLUMN `ICC_Trading_Revenue` COMMENT 'Instrument asset class. From revenue functions. `ISNULL(...,-1)` ג€” sentinel -1 for account-level fees (CashoutFee, ConversionFee, DormantFee, InterestFee). (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_management_kpis ALTER COLUMN `IsClubMember` COMMENT 'Player level ID from Fact_SnapshotCustomer. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi.vg_management_kpis ALTER COLUMN `MarketingRegion` COMMENT 'Marketing region name. From Dim_Country.MarketingRegionManualName joined via CountryID. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi.vg_management_kpis ALTER COLUMN `Net_Deposit_Amount` COMMENT 'Transaction amount in USD equivalent. Passthrough from sub-platform tables. Negative values may appear for withdrawals depending on platform source. (Tier 2 ג€” SP_DDR_Fact_Fact_MIMO_AllPlatforms)';
ALTER TABLE main.etoro_kpi.vg_management_kpis ALTER COLUMN `OpenVolumeFromIBAN` COMMENT 'Aggregated notional volume from position opens. `SUM(ftv.VolumeOpen)`. Source: `ISNULL(CAST(Dim_Position.Volume AS BIGINT), 0)` on open legs. (Tier 2 ג€” SP_DDR_Fact_Trading_Volumes_And_Amounts)';
ALTER TABLE main.etoro_kpi.vg_management_kpis ALTER COLUMN `RecurringInvestedAmount` COMMENT 'Aggregated invested amount from position opens. `SUM(ftv.InvestedAmountOpen)`. Source: `InitialAmountCents / 100.0` (0 for partial-close children). (Tier 2 ג€” SP_DDR_Fact_Trading_Volumes_And_Amounts)';
ALTER TABLE main.etoro_kpi.vg_management_kpis ALTER COLUMN `Stocks_Lending_Revenue` COMMENT 'Revenue metric dictionary ID. From `Dim_Revenue_Metrics.RevenueMetricID` via Metric text match. 12=Staking, 18=Options. Enables ID-based filtering. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';
ALTER TABLE main.etoro_kpi.vg_management_kpis ALTER COLUMN `Stocks_Trading_Revenue` COMMENT 'Futures contract flag. From functions or `Dim_Instrument.IsFuture` (AdminFee/SpotAdjust). `ISNULL(...,-1)`. (Tier 2 ג€” SP_DDR_Fact_Revenue_Generating_Actions)';

-- ----------------------------------------
