-- ----------------------------------------
ALTER TABLE main.etoro_kpi.vw_ftd_funnel ALTER COLUMN `CID` COMMENT 'Customer ID - platform-internal primary key. Assigned at registration. Unique within etoro DB. Used as the universal customer identifier across all tables. (Tier 1 ג€” Customer.CustomerStatic)';
ALTER TABLE main.etoro_kpi.vw_ftd_funnel ALTER COLUMN `CurrentVerificationLevel` COMMENT 'KYC verification level. FK to Dictionary.VerificationLevel. Values: 0=unverified (34.2%), 1=partial (12.4%), 2=intermediate (6.2%), 3=fully verified (47.1%). Default=0. (Tier 1 ג€” BackOffice.Customer)';
ALTER TABLE main.etoro_kpi.vw_ftd_funnel ALTER COLUMN `FirstTimeDeposit_DateTime` COMMENT 'Date of first deposit. DEFAULT=''19000101''. Updated from CustomerFinanceDB FTD data with FTDRecoveryDate logic. (Tier 2 ג€” SP_Dim_Customer)';
ALTER TABLE main.etoro_kpi.vw_ftd_funnel ALTER COLUMN `FirstTimeDepositAmountUSD` COMMENT 'Amount of first deposit (in USD). Updated from FTDAmountInUsd. (Tier 2 ג€” SP_Dim_Customer)';
ALTER TABLE main.etoro_kpi.vw_ftd_funnel ALTER COLUMN `GCID` COMMENT 'Group Customer ID - cross-product identity key linking the same person across eToro products/entities. NULL for older accounts predating GCID introduction. (Tier 1 ג€” Customer.CustomerStatic)';
ALTER TABLE main.etoro_kpi.vw_ftd_funnel ALTER COLUMN `IsPhoneVerified` COMMENT 'Whether phone is verified (VerificationStatusID IN (1,2) ג†’ 1). (Tier 2 ג€” SP_Dim_Customer)';
ALTER TABLE main.etoro_kpi.vw_ftd_funnel ALTER COLUMN `IsPopularInvestor` COMMENT 'eToro Popular Investor/Guru program status - whether the customer is an active copy trading strategy provider. FK to Dictionary.GuruStatus. (Tier 1 ג€” BackOffice.Customer)';
ALTER TABLE main.etoro_kpi.vw_ftd_funnel ALTER COLUMN `PhoneVerificationDate` COMMENT 'Date phone was verified. ''1900-01-01'' if not verified. (Tier 2 ג€” SP_Dim_Customer)';
ALTER TABLE main.etoro_kpi.vw_ftd_funnel ALTER COLUMN `Registration_DateTime` COMMENT 'Account registration date (renamed from Registered). Default=getdate(). (Tier 1 ג€” Customer.CustomerStatic)';

