ALTER TABLE main.etoro_kpi_prep.gold_de_user_dim_ddr_customer_dailystatus_scd ALTER COLUMN `DateRangeID` COMMENT 'Business date as YYYYMMDD integer. Delete/replace key. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi_prep.gold_de_user_dim_ddr_customer_dailystatus_scd ALTER COLUMN `FirstActionDateID` COMMENT 'Date of first trading action (YYYYMMDD). Sentinel 30000101 = no action. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi_prep.gold_de_user_dim_ddr_customer_dailystatus_scd ALTER COLUMN `FirstActionType` COMMENT 'First trading action type (e.g., ''Crypto'', ''Forex'', ''Stocks''). From Function_Population_First_Trading_Action. ''NoAction'' if none or future. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
