ALTER TABLE main.etoro_kpi_prep.gold_de_user_dim_ddr_customer_dailystatus_scd ALTER COLUMN `FirstIOBDateID` COMMENT 'First Instrument Open Balance date (YYYYMMDD). From Function_Population_First_Time_Funded. Added Aug 2025. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi_prep.gold_de_user_dim_ddr_customer_dailystatus_scd ALTER COLUMN `FirstIOBTime` COMMENT 'First IOB timestamp. From Function_Population_First_Time_Funded. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi_prep.gold_de_user_dim_ddr_customer_dailystatus_scd ALTER COLUMN `FirstTimeFunded` COMMENT 'First time funded today. CASE WHEN FirstFundedDateID = @dateID THEN 1. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi_prep.gold_de_user_dim_ddr_customer_dailystatus_scd ALTER COLUMN `FromDateID` COMMENT 'Business date as YYYYMMDD integer. Delete/replace key. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi_prep.gold_de_user_dim_ddr_customer_dailystatus_scd ALTER COLUMN `Global_FTD_Date` COMMENT 'Global first-time deposit datetime ג€” earliest across all platforms. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi_prep.gold_de_user_dim_ddr_customer_dailystatus_scd ALTER COLUMN `Global_FTD_DateID` COMMENT 'Global first-time deposit date (YYYYMMDD) ג€” earliest across all platforms. MIN(TP, IBAN, Options, MoneyFarm). (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi_prep.gold_de_user_dim_ddr_customer_dailystatus_scd ALTER COLUMN `Global_FTDA` COMMENT 'Global first-time deposit amount in USD ג€” amount of the earliest deposit. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi_prep.gold_de_user_dim_ddr_customer_dailystatus_scd ALTER COLUMN `IBAN_FTD_Date` COMMENT 'IBAN first-time deposit datetime. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi_prep.gold_de_user_dim_ddr_customer_dailystatus_scd ALTER COLUMN `IBAN_FTD_DateID` COMMENT 'IBAN (eMoney) first-time deposit date (YYYYMMDD). From Dim_Customer where FTDPlatformID=3. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi_prep.gold_de_user_dim_ddr_customer_dailystatus_scd ALTER COLUMN `IBAN_FTDA` COMMENT 'IBAN first-time deposit amount in USD. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi_prep.gold_de_user_dim_ddr_customer_dailystatus_scd ALTER COLUMN `IsChurned` COMMENT 'Currently funded. 1 when customer appears in Function_Population_Funded. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi_prep.gold_de_user_dim_ddr_customer_dailystatus_scd ALTER COLUMN `IsFunded` COMMENT 'Currently funded. 1 when customer appears in Function_Population_Funded. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi_prep.gold_de_user_dim_ddr_customer_dailystatus_scd ALTER COLUMN `IsWinBack` COMMENT 'Currently funded. 1 when customer appears in Function_Population_Funded. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi_prep.gold_de_user_dim_ddr_customer_dailystatus_scd ALTER COLUMN `MoneyFarm_FTD_Date` COMMENT 'MoneyFarm first-time deposit datetime. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi_prep.gold_de_user_dim_ddr_customer_dailystatus_scd ALTER COLUMN `MoneyFarm_FTD_DateID` COMMENT 'MoneyFarm first-time deposit date (YYYYMMDD). From Dim_Customer where FTDPlatformID=4. Added Nov 2025. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi_prep.gold_de_user_dim_ddr_customer_dailystatus_scd ALTER COLUMN `MoneyFarm_FTDA` COMMENT 'MoneyFarm first-time deposit amount in USD. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi_prep.gold_de_user_dim_ddr_customer_dailystatus_scd ALTER COLUMN `Options_FTD_Date` COMMENT 'Options platform first-time deposit datetime. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi_prep.gold_de_user_dim_ddr_customer_dailystatus_scd ALTER COLUMN `Options_FTD_DateID` COMMENT 'Options platform first-time deposit date (YYYYMMDD). From Dim_Customer where FTDPlatformID=2. Added Oct 2025. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi_prep.gold_de_user_dim_ddr_customer_dailystatus_scd ALTER COLUMN `Options_FTDA` COMMENT 'Options platform first-time deposit amount in USD. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi_prep.gold_de_user_dim_ddr_customer_dailystatus_scd ALTER COLUMN `Portfolio_Only` COMMENT 'Portfolio-only (has portfolio, not actively trading). From Function_Population_Portfolio_Only. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi_prep.gold_de_user_dim_ddr_customer_dailystatus_scd ALTER COLUMN `RealCID` COMMENT 'Real customer ID. Population from 5-layer waterfall (TP ג†’ IBAN ג†’ Options ג†’ OptionsMIMO ג†’ MoneyFarm). HASH distribution key. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi_prep.gold_de_user_dim_ddr_customer_dailystatus_scd ALTER COLUMN `ToDateID` COMMENT 'Real customer ID. Population from 5-layer waterfall (TP ג†’ IBAN ג†’ Options ג†’ OptionsMIMO ג†’ MoneyFarm). HASH distribution key. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.etoro_kpi_prep.gold_de_user_dim_ddr_customer_dailystatus_scd ALTER COLUMN `TP_External_FTDA` COMMENT 'TP external FTD amount ג€” excludes internal transfers (FundingTypeID ג‰  33). From MIMO aggregation. (Tier 2 ג€” SP_DDR_Customer_Daily_Status)';
