-- main.etoro_kpi_prep.instrument_conversion_rates_dwh (10 columns)
-- ----------------------------------------
ALTER TABLE main.etoro_kpi_prep.instrument_conversion_rates_dwh ALTER COLUMN `ConversionRate_Buy` COMMENT 'Raw bid price before spread adjustment. Mid-price reference. Compare to BidSpreaded to derive the spread. (Tier 2 - SP_Fact_CurrencyPriceWithSplit_DL_To_Synapse)';
ALTER TABLE main.etoro_kpi_prep.instrument_conversion_rates_dwh ALTER COLUMN `ConversionRate_Buy_Spreaded` COMMENT 'Spread-adjusted bid price for the instrument. The bid price with the broker spread applied. Used in P&L calculations for sell-side closing proceeds. (Tier 2 - SP_Fact_CurrencyPriceWithSplit_DL_To_Synapse)';
ALTER TABLE main.etoro_kpi_prep.instrument_conversion_rates_dwh ALTER COLUMN `ConversionRate_Sell` COMMENT 'The sell-side (denomination) currency. FK to DWH_dbo.Dim_Currency(CurrencyID). For forex: the quote currency (e.g., USD in EUR/USD). For stocks: the trading denomination currency (USD, EUR, GBX). Only 67 distinct values since many assets share the same denomination. (Tier 1 -- upstream wiki, Trade.Instrument)';
ALTER TABLE main.etoro_kpi_prep.instrument_conversion_rates_dwh ALTER COLUMN `ConversionRate_Sell_Spreaded` COMMENT 'Spread-adjusted ask (offer) price for the instrument. The ask price with the broker spread applied. Used in P&L calculations for buy-side opening cost. (Tier 2 - SP_Fact_CurrencyPriceWithSplit_DL_To_Synapse)';
ALTER TABLE main.etoro_kpi_prep.instrument_conversion_rates_dwh ALTER COLUMN `InstrumentDisplayName` COMMENT 'User-facing instrument display name from Trade.InstrumentMetaData. More descriptive than Name (e.g., ''Apple Inc.'' vs ''Apple''). NULL for instruments without metadata entries. (Tier 2 -- SP_Dim_Instrument, etoro_Trade_InstrumentMetaData)';
ALTER TABLE main.etoro_kpi_prep.instrument_conversion_rates_dwh ALTER COLUMN `InstrumentID` COMMENT 'Primary key identifying the tradeable instrument pair. Allocated by Trade.InstrumentAdd during instrument creation. Ranges from 0 (system placeholder) to ~21 million IDs allocated. Referenced by virtually every trading fact table and the Dim_Currency / Dim_HistorySplitRatio dimension tables. (Tier 1 -- upstream wiki, Trade.Instrument)';
ALTER TABLE main.etoro_kpi_prep.instrument_conversion_rates_dwh ALTER COLUMN `InstrumentType` COMMENT 'Text label for InstrumentTypeID -- DWH-computed via CASE: 1=Currencies, 2=Commodities, 4=Indices, 5=Stocks, 6=ETF, 10=Crypto Currencies, else=Other. Use InstrumentTypeID for filtering; InstrumentType for display. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.etoro_kpi_prep.instrument_conversion_rates_dwh ALTER COLUMN `InstrumentTypeID` COMMENT 'Instrument type category: 1=Currencies (forex), 2=Commodities, 4=Indices, 5=Stocks, 6=ETF, 10=Crypto Currencies. Note TypeIDs 3, 7, 8, 9 are unused gaps. Distribution: Stocks 82%, ETF 8%, Crypto 4%, Commodities 3%, Indices 2%, Currencies 1%. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.etoro_kpi_prep.instrument_conversion_rates_dwh ALTER COLUMN `Name` COMMENT 'Instrument name as defined in Trade.Instrument. For forex: pair notation (e.g., EUR/USD). For stocks: company name (e.g., Apple, Alphabet). For crypto: token name. This is the internal instrument name, not necessarily the display name shown to users (see InstrumentDisplayName). (Tier 3 -- live data, etoro.Trade.GetInstrument)';
ALTER TABLE main.etoro_kpi_prep.instrument_conversion_rates_dwh ALTER COLUMN `SellCurrency` COMMENT 'Text abbreviation of SellCurrencyID -- denormalized from Dictionary.Currency.Abbreviation. Example: USD, EUR, GBX (GBP pence). DWH-added for query convenience. (Tier 2 -- SP_Dim_Instrument)';

