ALTER TABLE main.etoro_kpi_prep.mv_revenue_trading ALTER COLUMN `Symbol` COMMENT 'Ticker symbol for the instrument (e.g., AAPL, EURUSD, BTCUSD). Used for display, search, and price feed identification. NULL for ID=0 placeholder and some instruments without formal ticker. (Tier 3 -- live data, etoro.Trade.GetInstrument)';

