ALTER TABLE main.etoro_kpi_prep.trading_vw_mimo_options_platform ALTER COLUMN `RealCID` COMMENT 'Customer ID - platform-internal primary key. Assigned at registration. Unique within etoro DB. Used as the universal customer identifier across all tables. (Tier 1 ג€” Customer.CustomerStatic)';

-- ----------------------------------------
-- main.etoro_kpi_prep.trading_vw_pnl_single_day (15 columns)
-- ----------------------------------------
ALTER TABLE main.etoro_kpi_prep.trading_vw_pnl_single_day ALTER COLUMN `CID` COMMENT 'Customer identifier for the position. (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.CID)';
ALTER TABLE main.etoro_kpi_prep.trading_vw_pnl_single_day ALTER COLUMN `DateID` COMMENT 'Snapshot date as YYYYMMDD; partition key. (Tier 3 -- SP_PositionPnL, CAST(CONVERT(CHAR(8),@dt,112) AS INT))';
ALTER TABLE main.etoro_kpi_prep.trading_vw_pnl_single_day ALTER COLUMN `HedgeServerID` COMMENT 'Hedge server for the position. (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.HedgeServerID)';
ALTER TABLE main.etoro_kpi_prep.trading_vw_pnl_single_day ALTER COLUMN `InstrumentID` COMMENT 'Traded instrument. (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.InstrumentID)';
ALTER TABLE main.etoro_kpi_prep.trading_vw_pnl_single_day ALTER COLUMN `IsBuy` COMMENT 'Long (1) vs short (0). (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.IsBuy)';
ALTER TABLE main.etoro_kpi_prep.trading_vw_pnl_single_day ALTER COLUMN `IsFuture` COMMENT 'Derived flag indicating if the instrument is a futures contract: 1=futures, 0=not futures. Computed in SP as CASE WHEN InstrumentID IN (SELECT InstrumentID FROM InstrumentGroups WHERE GroupID=25) THEN 1 ELSE 0. NULL for ID=0 placeholder. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.etoro_kpi_prep.trading_vw_pnl_single_day ALTER COLUMN `IsMarginTrade` COMMENT 'Modern settlement type from Dim_Position. (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.SettlementTypeID)';
ALTER TABLE main.etoro_kpi_prep.trading_vw_pnl_single_day ALTER COLUMN `IsSettled` COMMENT '1 = real asset, 0 = CFD asset. Rewound via PositionChangeLog (`ChangeTypeID = 13`) when applicable. (Tier 5 ג€” Expert Review)';
ALTER TABLE main.etoro_kpi_prep.trading_vw_pnl_single_day ALTER COLUMN `Leverage` COMMENT 'Position leverage. (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.Leverage)';
ALTER TABLE main.etoro_kpi_prep.trading_vw_pnl_single_day ALTER COLUMN `MirrorID` COMMENT 'Copy-trading mirror link when applicable. (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.MirrorID)';
ALTER TABLE main.etoro_kpi_prep.trading_vw_pnl_single_day ALTER COLUMN `PositionID` COMMENT 'Unique position key; Synapse distribution key. (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.PositionID)';
ALTER TABLE main.etoro_kpi_prep.trading_vw_pnl_single_day ALTER COLUMN `SettlementTypeID` COMMENT 'Modern settlement type from Dim_Position. (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.SettlementTypeID)';
ALTER TABLE main.etoro_kpi_prep.trading_vw_pnl_single_day ALTER COLUMN `UnrealizedPnLChange` COMMENT 'Unrealized P&L in USD; from `PnLInDollars` (replaces legacy formula). (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.PnLInDollars)';
ALTER TABLE main.etoro_kpi_prep.trading_vw_pnl_single_day ALTER COLUMN `UnrealizedPnLEnd` COMMENT 'Unrealized P&L in USD; from `PnLInDollars` (replaces legacy formula). (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.PnLInDollars)';
ALTER TABLE main.etoro_kpi_prep.trading_vw_pnl_single_day ALTER COLUMN `UnrealizedPnLStart` COMMENT 'Unrealized P&L in USD; from `PnLInDollars` (replaces legacy formula). (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.PnLInDollars)';

-- ----------------------------------------
-- main.etoro_kpi_prep.v_copyfund_positions (3 columns)
-- ----------------------------------------
ALTER TABLE main.etoro_kpi_prep.v_copyfund_positions ALTER COLUMN `MirrorTypeID` COMMENT '1=Regular, 2=CopyMe, 3=Social Index, 4=Fund (Dictionary.MirrorType). Determines mirror behavior. (Tier 1 ג€” Trade.Mirror)';
ALTER TABLE main.etoro_kpi_prep.v_copyfund_positions ALTER COLUMN `ParentCID` COMMENT 'Leader customer ID. The user whose trades are copied. Trade.GetActiveCopiersForParents filters by ParentCID. (Tier 1 ג€” Trade.Mirror)';
ALTER TABLE main.etoro_kpi_prep.v_copyfund_positions ALTER COLUMN `ParentUserName` COMMENT 'Leader username at mirror creation. Denormalized for display; Trade.RegisterMirror passes from caller. (Tier 1 ג€” Trade.Mirror)';

-- ----------------------------------------
-- main.etoro_kpi_prep.v_dim_instrument_enriched (48 columns)
-- ----------------------------------------
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `ADV_Last3Months` COMMENT 'Average Daily Trading Volume over the trailing 3 months (TTM), from Rankings StockInfo MetadataID=8557. In shares/units. NULL for non-stock instruments or instruments without Rankings coverage. Example: Apple ~48M shares/day. (Tier 2 -- SP_Dim_Instrument, Rankings_StockInfo)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `AllowBuy` COMMENT 'Flag indicating if long (buy) positions can currently be opened: 1=allowed, 0=disabled. Cast from bit. NULL for ID=0 placeholder. Instruments may be buy-disabled due to regulatory restrictions, risk management, or market conditions. (Tier 2 -- SP_Dim_Instrument, etoro.Trade.GetInstrument)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `AllowSell` COMMENT 'Flag indicating if short (sell) positions can currently be opened: 1=allowed, 0=disabled. Cast from bit. NULL for ID=0 placeholder. Many regulated markets prohibit short selling for retail clients. (Tier 2 -- SP_Dim_Instrument, etoro.Trade.GetInstrument)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `AssetClass` COMMENT 'Bloomberg-style asset class classification from Ext_Dim_Instrument_Classification_Static (e.g., Technology, Consumer Services, Finance). More granular than InstrumentType. NULL for non-stock instruments or instruments not in the classification static table. (Tier 2 -- SP_Dim_Instrument, post-load UPDATE)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `BonusCreditUsePercent` COMMENT 'Percentage of bonus credit that can be applied to trading this instrument, from Trade.ProviderToInstrument. Lower values restrict bonus usage for high-risk/volatile instruments. NULL for instruments without ProviderToInstrument mapping. (Tier 3 -- live data, etoro_Trade_ProviderToInstrument)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `BuyCurrency` COMMENT 'Text abbreviation of BuyCurrencyID -- denormalized from Dictionary.Currency.Abbreviation via SP JOIN. Example: EUR, AAPL, BTC. DWH-added for query convenience. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `BuyCurrencyID` COMMENT 'The buy-side asset of the instrument pair. FK to DWH_dbo.Dim_Currency(CurrencyID). For forex: the base currency. For stocks/ETFs/crypto: the asset''s own CurrencyID in Dim_Currency (BuyCurrencyID = InstrumentID for stocks). (Tier 1 -- upstream wiki, Trade.Instrument)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `CompanyInfo` COMMENT 'Free-text company description from Trade.InstrumentMetaData. May contain multi-sentence business descriptions of the company. NULL for non-company instruments (forex, commodities, indices). (Tier 3 -- live data, etoro_Trade_InstrumentMetaData)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `CUSIP` COMMENT 'Committee on Uniform Securities Identification Procedures number -- 9-character code for US/Canadian securities. Used for clearing, settlement, and regulatory reporting. NULL for non-US instruments and instruments without CUSIP. (Tier 2 -- SP_Dim_Instrument, etoro_Trade_InstrumentCusip)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `DollarRatio` COMMENT 'Price scaling factor for USD normalization. Most instruments = 1. JPY pairs = 100 (because JPY is quoted at 100x the numeric value of other currencies). Used in P&L and conversion rate calculations across the platform. (Tier 1 -- upstream wiki, Trade.Instrument)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `DWHInstrumentID` COMMENT 'Always equal to InstrumentID -- redundant copy following the DWH DWH{X}ID pattern. Use InstrumentID for all JOINs. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `eToroMarginPerLot` COMMENT 'eToro''s own margin requirement per lot in asset currency (InitialMarginInAssetCurrency from Trade.ProviderToInstrument). eToro''s internal margin may differ from the provider''s margin. NULL for instruments without ProviderToInstrument mapping. (Tier 3 -- live data, etoro_Trade_ProviderToInstrument)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `Exchange` COMMENT 'Stock exchange name from Trade.InstrumentMetaData (e.g., Nasdaq, NYSE, LSE). NULL for non-stock instruments. (Tier 3 -- live data, etoro_Trade_InstrumentMetaData)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `Industry` COMMENT 'Industry classification string from Trade.InstrumentMetaData. Text description (e.g., ''Internet'', ''Software''). Similar to but may differ from IndustryGroup (Bloomberg). NULL for non-stock instruments or instruments without metadata. (Tier 3 -- live data, etoro_Trade_InstrumentMetaData)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `IndustryGroup` COMMENT 'Bloomberg-style industry group within AssetClass (e.g., Computers, Internet, Banks). Sub-classification of AssetClass. NULL for non-stock instruments or instruments not in the classification table. (Tier 2 -- SP_Dim_Instrument, post-load UPDATE)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `InsertDate` COMMENT 'ETL load timestamp -- set to GETDATE() by SP_Dim_Instrument, same as UpdateDate. Both reflect the daily load time. Does NOT reflect production insertion date. NULL only for ID=0 placeholder. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `InstrumentDisplayName` COMMENT 'User-facing instrument display name from Trade.InstrumentMetaData. More descriptive than Name (e.g., ''Apple Inc.'' vs ''Apple''). NULL for instruments without metadata entries. (Tier 2 -- SP_Dim_Instrument, etoro_Trade_InstrumentMetaData)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `InstrumentID` COMMENT 'Primary key identifying the tradeable instrument pair. Allocated by Trade.InstrumentAdd during instrument creation. Ranges from 0 (system placeholder) to ~21 million IDs allocated. Referenced by virtually every trading fact table and the Dim_Currency / Dim_HistorySplitRatio dimension tables. (Tier 1 -- upstream wiki, Trade.Instrument)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `InstrumentType` COMMENT 'Text label for InstrumentTypeID -- DWH-computed via CASE: 1=Currencies, 2=Commodities, 4=Indices, 5=Stocks, 6=ETF, 10=Crypto Currencies, else=Other. Use InstrumentTypeID for filtering; InstrumentType for display. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `InstrumentTypeID` COMMENT 'Instrument type category: 1=Currencies (forex), 2=Commodities, 4=Indices, 5=Stocks, 6=ETF, 10=Crypto Currencies. Note TypeIDs 3, 7, 8, 9 are unused gaps. Distribution: Stocks 82%, ETF 8%, Crypto 4%, Commodities 3%, Indices 2%, Currencies 1%. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `IsFuture` COMMENT 'Derived flag indicating if the instrument is a futures contract: 1=futures, 0=not futures. Computed in SP as CASE WHEN InstrumentID IN (SELECT InstrumentID FROM InstrumentGroups WHERE GroupID=25) THEN 1 ELSE 0. NULL for ID=0 placeholder. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `ISINCode` COMMENT 'International Securities Identification Number -- 12-character alphanumeric code standardized by ISO 6166 (e.g., US0378331005 for Apple). NULL for forex, commodities, and instruments without ISIN. Country prefix + national code + check digit. (Tier 2 -- SP_Dim_Instrument, etoro_Trade_InstrumentMetaData)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `ISINCountryCode` COMMENT 'Country code prefix from the ISIN (first 2 characters). Indicates the country of registration (e.g., US, DE, GB). NULL when ISINCode is NULL. (Tier 2 -- SP_Dim_Instrument, etoro_Trade_InstrumentMetaData)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `IsMajor` COMMENT 'Text version of IsMajorID -- DWH CASE computed: IsMajorID=1->''Yes'', 0->''No''. Use for display. Affects spread calculations and regulatory leverage caps (ESMA allows higher leverage for major forex). (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `IsMajorID` COMMENT 'Integer representation of the production IsMajor flag (0 or 1). 1=major instrument (6,963 instruments -- all major forex pairs and many popular stocks). 0=non-major (8,743 instruments). Renamed from production IsMajor to distinguish from the text version. Use for filtering. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `MKTcap` COMMENT 'Market capitalization in USD from Rankings StockInfo (MetadataID=8735 for equities; fallback MetadataID=9315 CryptoMarketCap for crypto). NULL for forex, commodities, and indices. Example: Apple ~3.8T USD. (Tier 2 -- SP_Dim_Instrument, Rankings_StockInfo)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `Multiplier` COMMENT 'Futures contract size multiplier from Trade.FuturesMetaData. Determines how many units of the underlying asset one contract represents. NULL for non-futures instruments. (Tier 2 -- SP_Dim_Instrument, etoro_Trade_FuturesMetaData)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `Name` COMMENT 'Instrument name as defined in Trade.Instrument. For forex: pair notation (e.g., EUR/USD). For stocks: company name (e.g., Apple, Alphabet). For crypto: token name. This is the internal instrument name, not necessarily the display name shown to users (see InstrumentDisplayName). (Tier 3 -- live data, etoro.Trade.GetInstrument)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `OperationMode` COMMENT 'Trading operation mode: 0=Standard mode (default, ~15,600 instruments), 1=Alternate mode (~83 instruments, primarily European stock CFDs traded in non-USD denomination currencies). Controls how the trading engine processes orders. (Tier 1 -- upstream wiki, Trade.Instrument)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `PipDifferenceThreshold` COMMENT 'Maximum allowed pip difference threshold for price validation. If a new price deviates more than this threshold from the previous price, it may be flagged as suspicious. NULL for some instruments. (Tier 1 -- upstream wiki, Trade.Instrument)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `PlatformIndustry` COMMENT 'eToro platform industry classification from Rankings StockInfo MetadataID=8280. More granular than PlatformSector. NULL for non-equity instruments or instruments without Rankings coverage. (Tier 2 -- SP_Dim_Instrument, Rankings_StockInfo)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `PlatformSector` COMMENT 'eToro platform sector classification from Rankings StockInfo MetadataID=8436. May differ from Bloomberg AssetClass. NULL for non-equity instruments or instruments without Rankings coverage. (Tier 2 -- SP_Dim_Instrument, Rankings_StockInfo)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `Precision` COMMENT 'Decimal precision for price display and trading (number of decimal places), from Trade.ProviderToInstrument. Determines how many decimals are shown in the UI and used in calculations. NULL for instruments without ProviderToInstrument mapping. (Tier 3 -- live data, etoro_Trade_ProviderToInstrument)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `ProviderID` COMMENT 'Liquidity provider identifier from Trade.ProviderToInstrument. Identifies which external market maker or broker provides pricing/liquidity for this instrument. NULL for instruments without a provider mapping. (Tier 3 -- live data, etoro_Trade_ProviderToInstrument)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `ProviderMarginPerLot` COMMENT 'Initial margin requirement per lot in the provider''s terms, from Trade.FuturesInstrumentsInitialMarginByProviderMapping. Primarily relevant for futures instruments. NULL for non-futures or instruments without provider margin data. (Tier 3 -- live data, FuturesInstrumentsInitialMarginByProviderMapping)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `ReceivedOnPriceServer` COMMENT 'First timestamp when the instrument was observed on the price server (from Ext_Dim_Instrument_ReceivedOnPriceServerStatic). Set once and never updated (static history). NULL for instruments not yet priced or newly added instruments that have not yet appeared in price feeds. (Tier 2 -- SP_Dim_Instrument, post-load UPDATE)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `SellCurrency` COMMENT 'Text abbreviation of SellCurrencyID -- denormalized from Dictionary.Currency.Abbreviation. Example: USD, EUR, GBX (GBP pence). DWH-added for query convenience. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `SellCurrencyID` COMMENT 'The sell-side (denomination) currency. FK to DWH_dbo.Dim_Currency(CurrencyID). For forex: the quote currency (e.g., USD in EUR/USD). For stocks: the trading denomination currency (USD, EUR, GBX). Only 67 distinct values since many assets share the same denomination. (Tier 1 -- upstream wiki, Trade.Instrument)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `SettlementTime` COMMENT 'Daily or periodic settlement time for the instrument, from Trade.ProviderToInstrument, formatted as TIME via SP DATEPART conversion. Primarily relevant for futures and CFD instruments with defined settlement windows. NULL for instruments without settlement time defined. (Tier 3 -- live data, etoro_Trade_ProviderToInstrument)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `SharesOutStanding` COMMENT 'Total shares outstanding in units from Rankings StockInfo MetadataID=8444. Annual figure. NULL for non-equity instruments. Example: Apple ~14.7B shares. (Tier 2 -- SP_Dim_Instrument, Rankings_StockInfo)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `StatusID` COMMENT 'Hardcoded to 1 for all real rows by SP_Dim_Instrument. NULL only for ID=0 placeholder. Conveys no business information. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `Symbol` COMMENT 'Ticker symbol for the instrument (e.g., AAPL, EURUSD, BTCUSD). Used for display, search, and price feed identification. NULL for ID=0 placeholder and some instruments without formal ticker. (Tier 3 -- live data, etoro.Trade.GetInstrument)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `SymbolFull` COMMENT 'Full ticker symbol (may be longer than Symbol), from Trade.InstrumentMetaData. Used for data provider integrations that require fully qualified symbols. NULL for instruments without metadata. (Tier 3 -- live data, etoro_Trade_InstrumentMetaData)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `Tradable` COMMENT 'Flag indicating if the instrument is currently tradable: 1=tradable, 0=not tradable. CAST from production bit. NULL for ID=0 placeholder. An instrument may exist but be non-tradable due to regulatory, market, or operational reasons. (Tier 2 -- SP_Dim_Instrument, etoro.Trade.GetInstrument)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `Tradeable` COMMENT 'Flag (0/1) indicating if the instrument is visible only to internal eToro users (not shown to retail customers). Cast from bit. Used for instruments under development, testing, or institutional-only. NULL for ID=0 placeholder. (Tier 3 -- live data, etoro.Trade.GetInstrument)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `TradeRange` COMMENT 'Allowed trade range in pips for pending orders. Determines how far from market price a limit/stop order can be placed. Set during instrument creation. (Tier 1 -- upstream wiki, Trade.Instrument)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `UpdateDate` COMMENT 'ETL load timestamp -- set to GETDATE() by SP_Dim_Instrument on each daily reload. Does NOT reflect production modification date. NULL only for ID=0 placeholder. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.etoro_kpi_prep.v_dim_instrument_enriched ALTER COLUMN `VisibleInternallyOnly` COMMENT 'Flag (0/1) indicating if the instrument is visible only to internal eToro users (not shown to retail customers). Cast from bit. Used for instruments under development, testing, or institutional-only. NULL for ID=0 placeholder. (Tier 3 -- live data, etoro.Trade.GetInstrument)';

-- ----------------------------------------
-- main.etoro_kpi_prep.v_fact_customeraction (72 columns)
-- ----------------------------------------
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `ActionTypeID` COMMENT 'Event type classifier. References `DWH_dbo.Dim_ActionType.ActionTypeID` ג€” JOIN for Name, Category, CategoryID. See Section 2.1 for full mapping. Key filter column ג€” drives which other columns are populated. (Tier 1 ג€” ETL-derived from CreditTypeID/source)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `Amount` COMMENT 'Position size in currency. Must be >= 0. Stored in dollars (PositionOpen divides by 100 from cents). (Tier 1 ג€” Trade.PositionTbl)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `BonusTypeID` COMMENT 'Bonus type for bonus events (ActionTypeID=9). 0 for non-bonus events. References `DWH_dbo.Dim_BonusType.BonusTypeID` ג€” JOIN for Name, IsWithdrawable, IsActive. (Tier 5 ג€” domain expert)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `CampaignID` COMMENT 'Marketing campaign identifier. 0 if not campaign-related. References `DWH_dbo.Dim_Campaign.CampaignID` ג€” JOIN for Code, Description, StartDate, EndDate, MaxBonusAmount, IsActive. (Tier 5 ג€” domain expert)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `CaseID` COMMENT 'CRM case identifier for ActionTypeID=31 (Open CRM Case). 0 otherwise. (Tier 1 ג€” CRM)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `Commission` COMMENT 'Open commission in dollars. PositionOpen stores @Commission/100 (cents to dollars). (Tier 1 ג€” Trade.PositionTbl)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `CommissionByUnits` COMMENT 'Prorated commission for partial close. Formula: (AmountInUnitsDecimal / InitialUnits) * Commission. Used for partial-close PnL. (Tier 1 ג€” Trade.Position)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `CommissionOnClose` COMMENT 'Commission charged on close. DWH note: adjusted by SP_Dim_Position when position is reopened; CommissionOnCloseOrig stores the pre-adjustment value. (Tier 1 ג€” Trade.PositionTbl)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `CommissionOnCloseOrig` COMMENT 'Original CommissionOnClose before reopen adjustments. ETL: CASE WHEN ReopenForPositionID IS NOT NULL THEN CommissionOnClose ELSE 0. (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `CompensationReasonID` COMMENT 'Compensation reason for compensation events (ActionTypeID=36) and position opens (for airdrop identification). References `BackOffice.CompensationReason`. 0 for non-compensation events. (Tier 1 ג€” History.Credit, updated 2025-12-21)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `CountryIDByIP` COMMENT 'Country determined by IP geolocation. Populated for logins and registrations. References `DWH_dbo.Dim_Country.CountryID` ג€” JOIN for country name. Also see `DWH_dbo.Dim_CountryIP` for IP-to-country resolution. (Tier 5 ג€” domain expert)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `CreditID` COMMENT 'Reference to the source `History.Credit.CreditID`. Enables join back to credit history for audit. (Tier 1 ג€” History.Credit, added 2025-07)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `DateID` COMMENT 'Date of the action as integer YYYYMMDD. Derived from `Occurred`. Part of nonclustered indexes. (Tier 2 ג€” ETL-computed)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `DemoCID` COMMENT 'Demo-account Customer ID. Always 0 in this table (real accounts only). (Tier 3 ג€” ETL-assigned)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `DepositID` COMMENT 'Deposit transaction identifier. NULL for non-deposit events. (Tier 1 ג€” History.Credit)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `Description` COMMENT 'Human-readable description. Populated mainly for ActionTypeID=35 (fees): "Over night fee", "Payment caused by dividend", "Weekend fee", "OpenTotalFees", "CloseTotalFees", "SDRT Charge". For ActionTypeID=32: "edit stop loss by customer". For deposits: "Processed By eToro.Payments.Deposit", etc. (Tier 1 ג€” History.Credit, added 2024-08)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `DividendID` COMMENT 'Dividend event identifier for dividend-related fees. NULL for non-dividend events. (Tier 1 ג€” Trade positions)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `DLTClose` COMMENT 'DLT flag at close. Added 2024-06-02. NULL for open positions and older positions. (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `DLTOpen` COMMENT 'DLT flag at open. Added 2024-06-02 (Ofir A). (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `DurationInSeconds` COMMENT 'Duration of a login session in seconds. NULL for non-login events. (Tier 1 ג€” Billing.Login)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `FullCommission` COMMENT 'Full commission including spread. PositionOpen stores @FullCommission/100. (Tier 1 ג€” Trade.PositionTbl)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `FullCommissionByUnits` COMMENT 'Prorated full commission for partial close. Same proration formula as CommissionByUnits applied to FullCommission. (Tier 1 ג€” Trade.Position)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `FullCommissionOnClose` COMMENT 'Full commission on close. DWH note: adjusted by SP_Dim_Position when position is reopened; FullCommissionOnCloseOrig stores the pre-adjustment value. (Tier 1 ג€” Trade.PositionTbl)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `FullCommissionOnCloseOrig` COMMENT 'Original FullCommissionOnClose before reopen. ETL default 0. (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `FundingTypeID` COMMENT 'Payment method used for deposits/withdrawals. 0 for non-deposit events. References `DWH_dbo.Dim_FundingType.FundingTypeID` ג€” JOIN for Name, IsNewStyle, IsSingleFunding, IsCashoutActive. (Tier 5 ג€” domain expert)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `GCID` COMMENT 'Global Customer ID ג€” the platform-wide unique customer identifier. References `Dim_Customer.GCID`. (Tier 1 ג€” Customer.CustomerStatic)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `HistoryID` COMMENT 'Intended as a unique key but contains duplicates ג€” NOT reliable as a primary/unique identifier. Do not use for JOINs, deduplication, or row identification. Has no practical use for analysts. (Tier 5 ג€” domain expert)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `InitialUnits` COMMENT 'Original unit count at open. Used for partial close ratio. (Tier 1 ג€” Trade.PositionTbl)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `InstrumentID` COMMENT 'FK to Trade.Instrument. Financial instrument being traded. (Tier 1 ג€” Trade.PositionTbl)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `IPNumber` COMMENT 'IP address of the customer as a numeric value. Populated for logins and registrations. (Tier 1 ג€” STS/Billing.Login)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `IsAirDrop` COMMENT '1=position was created via an airdrop event (crypto). ETL-computed: JOIN to etoro_Trade_PositionAirdropLog. NULL=not an airdrop. (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `IsAnonymousIP` COMMENT 'Anonymous IP flag: 1 = connection via anonymous proxy/VPN. NULL for most rows. (Tier 1 ג€” IP geolocation)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `IsBuy` COMMENT '1 = Long/Buy (profit when price rises), 0 = Short/Sell. (Tier 1 ג€” Trade.PositionTbl)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `IsDiscounted` COMMENT '1=position received a discounted rate. DWH note: CAST from bit to int. (Tier 1 ג€” Trade.PositionTbl)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `IsFeeDividend` COMMENT 'Fee sub-type for ActionTypeID=35: 1=overnight/weekend fee, 2=dividend, 3=SDRT, 4=ticket fees (OpenTotalFees/CloseTotalFees). NULL for non-fee events. See Section 2.2 and DSM-1463. (Tier 2 ג€” ETL-derived from Description)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `IsFTD` COMMENT 'First-Time Deposit flag: 1 = this is the customer''s first deposit. NULL for non-deposit events. (Tier 2 ג€” ETL-computed)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `IsPartialCloseChild` COMMENT '1=this position is the child (remainder) of a partial close event. (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `IsPartialCloseParent` COMMENT '1=this position was partially closed (is the parent in a partial close event). (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `IsPlug` COMMENT 'Deprecated/unused column. Always NULL. (Tier 5 ג€” domain expert)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `IsReal` COMMENT 'Account type flag. Always 1 in this table (real accounts only). (Tier 3 ג€” ETL-assigned)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `IsRedeem` COMMENT 'Redeem flag. 0=not a redeem, 1=is a redeem. NULL for non-position events. Same meaning as `Dim_Position.IsRedeem` (via RedeemStatus mapping). (Tier 3 ג€” ETL-derived)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `IsReOpen` COMMENT '1=this position was reopened from ReopenForPositionID. ETL-computed: CASE WHEN ReopenForPositionID IS NOT NULL THEN 1. Default 0. (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `IsSettled` COMMENT '1 = real asset, 0 = CFD asset. (Tier 5 ג€” Expert Review)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `Leverage` COMMENT 'Leverage multiplier (1, 5, 10, etc.). Determines margin and settlement type. (Tier 1 ג€” Trade.PositionTbl)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `LoginID` COMMENT 'Login session identifier from `Billing.Login`. 0 for non-login events. (Tier 1 ג€” Billing.Login)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `MirrorID` COMMENT 'UTC timestamp when the action occurred. For position opens: when position was opened. For logins: login time. For credits: when the credit was recorded. (Tier 1 ג€” source-dependent)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `MoveMoneyReasonID` COMMENT 'Reason for money movement: 1=Adjustment, 5=InternalTransfer Trade, 6=InternalTransfer, 8=Recurring Deposit, 9=Recurring Investment. References `Dictionary.MoveMoneyReason`. (Tier 1 ג€” History.Credit)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `NetProfit` COMMENT 'Realized PnL. 0 when open; set on close. In position currency. (Tier 1 ג€” Trade.PositionTbl)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `Occurred` COMMENT 'UTC timestamp when the action occurred. For position opens: when position was opened. For logins: login time. For credits: when the credit was recorded. (Tier 1 ג€” source-dependent)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `OpenMarkupByUnits` COMMENT 'Prorated open markup for partial close. Formula: OpenMarkup * AmountInUnitsDecimal / InitialUnits. (Tier 1 ג€” Trade.Position)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `OriginalPositionID` COMMENT 'Original position ID for positions split by partial close. (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `PaymentStatusID` COMMENT 'Payment processing status for deposit/cashout events. NULL for non-payment events. References `DWH_dbo.Dim_PaymentStatus.PaymentStatusID` ג€” JOIN for Name. (Tier 5 ג€” domain expert)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `PlatformID` COMMENT 'Product/platform identifier ג€” badly named, actually references `Dim_Product.ProductID` (not a standalone platform enum). Resolves to Product, Platform, and SubPlatform via JOIN to `DWH_dbo.Dim_Product`. Only populated for ActionTypeID=14 (logins) and 41 (registrations). (Tier 5 ג€” domain expert)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `PlatformTypeID` COMMENT 'Legacy platform type. 0=default (most rows), 99=STS source. Values 1-9 for specific platforms. (Tier 3 ג€” ETL-assigned)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `PositionID` COMMENT 'Human-readable description. Populated mainly for ActionTypeID=35 (fees): "Over night fee", "Payment caused by dividend", "Weekend fee", "OpenTotalFees", "CloseTotalFees", "SDRT Charge". For ActionTypeID=32: "edit stop loss by customer". For deposits: "Processed By eToro.Payments.Deposit", etc. (Tier 1 ג€” History.Credit, added 2024-08)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `PostID` COMMENT 'Social post/comment GUID for social engagement events (ActionTypeID 21-26). NULL for non-social events. (Tier 1 ג€” Social platform)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `PostRootID` COMMENT 'Root post ID for social engagement events. NULL for non-social events. (Tier 1 ג€” Social platform)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `PreviousOccurred` COMMENT 'Deprecated/unused column. NULL for most rows ג€” not reliably populated. Do not use. (Tier 5 ג€” domain expert)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `ProxyType` COMMENT 'Proxy classification: DCH=datacenter, VPN=VPN, PUB=public proxy, SES=session proxy, TOR=Tor exit node, WEB=web proxy. NULL for non-proxy connections. (Tier 1 ג€” STS)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `RealCID` COMMENT 'Real-account Customer ID. HASH distribution key. References `Dim_Customer.RealCID`. Each customer has one real CID. (Tier 1 ג€” Customer.CustomerStatic)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `RedeemID` COMMENT 'Billing.Redeem reference when position closed via redeem. (Tier 1 ג€” Trade.PositionTbl)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `RedeemStatus` COMMENT 'Redemption state. Billing.Redeem integration. (Tier 1 ג€” Trade.PositionTbl)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `RegulationIDOnOpen` COMMENT 'Regulatory jurisdiction ID at time of position open. ETL-computed via JOIN to etoro_History_BackOfficeCustomer (customer''s regulation history). ISNULL(..., 0) when no regulation match found. (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `ReopenForPositionID` COMMENT 'When position was reopened: references the erroneously closed PositionID. (Tier 1 ג€” Trade.PositionTbl)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `SessionID` COMMENT 'STS session identifier for logins and position opens. For manual opens: from login session. For copy opens: from mirror session. NULL for other events. (Tier 1 ג€” STS)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `SettlementTypeID` COMMENT 'Modern settlement classification. Dictionary.SettlementTypes: 0=CFD, 1=REAL, 2=TRS, 3=CMT, 4=REAL_FUTURES, 5=MARGIN_TRADE. Replaces IsSettled. (Tier 1 ג€” Trade.PositionTbl)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `StatusID` COMMENT 'Row status. Nearly always 1 (active). NULL for ~2M rows. (Tier 3 ג€” ETL-assigned)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `TicketFeeAction` COMMENT 'Human-readable description. Populated mainly for ActionTypeID=35 (fees): "Over night fee", "Payment caused by dividend", "Weekend fee", "OpenTotalFees", "CloseTotalFees", "SDRT Charge". For ActionTypeID=32: "edit stop loss by customer". For deposits: "Processed By eToro.Payments.Deposit", etc. (Tier 1 ג€” History.Credit, added 2024-08)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `TimeID` COMMENT 'Hour of the action (0-23). Derived from `DATEPART(HOUR, Occurred)`. (Tier 2 ג€” ETL-computed)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `UpdateDate` COMMENT 'UTC timestamp of the last DWH ETL update for this row. Set to `GETUTCDATE()` during each ETL run. (Tier 2 ג€” ETL-assigned)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `WithdrawID` COMMENT 'Withdrawal request ID for cashout events. 0 for non-cashout events. (Tier 1 ג€” History.Credit)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction ALTER COLUMN `WithdrawPaymentID` COMMENT 'Payment processing ID for cashout/withdrawal events. 0 for non-cashout events. Used to deduplicate WithdrawProcessingID rows in the ETL. (Tier 1 ג€” History.Credit)';

