ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `ActionTypeID` COMMENT 'Event type classifier. References `DWH_dbo.Dim_ActionType.ActionTypeID` ג€” JOIN for Name, Category, CategoryID. See Section 2.1 for full mapping. Key filter column ג€” drives which other columns are populated. (Tier 1 ג€” ETL-derived from CreditTypeID/source)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `Amount` COMMENT 'Position size in currency. Must be >= 0. Stored in dollars (PositionOpen divides by 100 from cents). (Tier 1 ג€” Trade.PositionTbl)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `BonusTypeID` COMMENT 'Bonus type for bonus events (ActionTypeID=9). 0 for non-bonus events. References `DWH_dbo.Dim_BonusType.BonusTypeID` ג€” JOIN for Name, IsWithdrawable, IsActive. (Tier 5 ג€” domain expert)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `CampaignID` COMMENT 'Marketing campaign identifier. 0 if not campaign-related. References `DWH_dbo.Dim_Campaign.CampaignID` ג€” JOIN for Code, Description, StartDate, EndDate, MaxBonusAmount, IsActive. (Tier 5 ג€” domain expert)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `CaseID` COMMENT 'CRM case identifier for ActionTypeID=31 (Open CRM Case). 0 otherwise. (Tier 1 ג€” CRM)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `Commission` COMMENT 'Open commission in dollars. PositionOpen stores @Commission/100 (cents to dollars). (Tier 1 ג€” Trade.PositionTbl)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `CommissionByUnits` COMMENT 'Prorated commission for partial close. Formula: (AmountInUnitsDecimal / InitialUnits) * Commission. Used for partial-close PnL. (Tier 1 ג€” Trade.Position)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `CommissionOnClose` COMMENT 'Commission charged on close. DWH note: adjusted by SP_Dim_Position when position is reopened; CommissionOnCloseOrig stores the pre-adjustment value. (Tier 1 ג€” Trade.PositionTbl)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `CommissionOnCloseOrig` COMMENT 'Original CommissionOnClose before reopen adjustments. ETL: CASE WHEN ReopenForPositionID IS NOT NULL THEN CommissionOnClose ELSE 0. (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `CompensationReasonID` COMMENT 'Compensation reason for compensation events (ActionTypeID=36) and position opens (for airdrop identification). References `BackOffice.CompensationReason`. 0 for non-compensation events. (Tier 1 ג€” History.Credit, updated 2025-12-21)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `CountryIDByIP` COMMENT 'Country determined by IP geolocation. Populated for logins and registrations. References `DWH_dbo.Dim_Country.CountryID` ג€” JOIN for country name. Also see `DWH_dbo.Dim_CountryIP` for IP-to-country resolution. (Tier 5 ג€” domain expert)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `CreditID` COMMENT 'Reference to the source `History.Credit.CreditID`. Enables join back to credit history for audit. (Tier 1 ג€” History.Credit, added 2025-07)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `DateID` COMMENT 'Date of the action as integer YYYYMMDD. Derived from `Occurred`. Part of nonclustered indexes. (Tier 2 ג€” ETL-computed)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `DemoCID` COMMENT 'Demo-account Customer ID. Always 0 in this table (real accounts only). (Tier 3 ג€” ETL-assigned)';
