ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `LoginID` COMMENT 'Login session identifier from `Billing.Login`. 0 for non-login events. (Tier 1 ג€” Billing.Login)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `MirrorID` COMMENT 'UTC timestamp when the action occurred. For position opens: when position was opened. For logins: login time. For credits: when the credit was recorded. (Tier 1 ג€” source-dependent)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `MoveMoneyReasonID` COMMENT 'Reason for money movement: 1=Adjustment, 5=InternalTransfer Trade, 6=InternalTransfer, 8=Recurring Deposit, 9=Recurring Investment. References `Dictionary.MoveMoneyReason`. (Tier 1 ג€” History.Credit)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `NetProfit` COMMENT 'Realized PnL. 0 when open; set on close. In position currency. (Tier 1 ג€” Trade.PositionTbl)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `Occurred` COMMENT 'UTC timestamp when the action occurred. For position opens: when position was opened. For logins: login time. For credits: when the credit was recorded. (Tier 1 ג€” source-dependent)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `OpenMarkupByUnits` COMMENT 'Prorated open markup for partial close. Formula: OpenMarkup * AmountInUnitsDecimal / InitialUnits. (Tier 1 ג€” Trade.Position)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `OriginalPositionID` COMMENT 'Original position ID for positions split by partial close. (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `PaymentStatusID` COMMENT 'Payment processing status for deposit/cashout events. NULL for non-payment events. References `DWH_dbo.Dim_PaymentStatus.PaymentStatusID` ג€” JOIN for Name. (Tier 5 ג€” domain expert)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `PlatformID` COMMENT 'Product/platform identifier ג€” badly named, actually references `Dim_Product.ProductID` (not a standalone platform enum). Resolves to Product, Platform, and SubPlatform via JOIN to `DWH_dbo.Dim_Product`. Only populated for ActionTypeID=14 (logins) and 41 (registrations). (Tier 5 ג€” domain expert)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `PlatformTypeID` COMMENT 'Legacy platform type. 0=default (most rows), 99=STS source. Values 1-9 for specific platforms. (Tier 3 ג€” ETL-assigned)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `PositionID` COMMENT 'Event type classifier. References `DWH_dbo.Dim_ActionType.ActionTypeID` ג€” JOIN for Name, Category, CategoryID. See Section 2.1 for full mapping. Key filter column ג€” drives which other columns are populated. (Tier 1 ג€” ETL-derived from CreditTypeID/source)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `PostID` COMMENT 'Social post/comment GUID for social engagement events (ActionTypeID 21-26). NULL for non-social events. (Tier 1 ג€” Social platform)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `PostRootID` COMMENT 'Root post ID for social engagement events. NULL for non-social events. (Tier 1 ג€” Social platform)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `PreviousOccurred` COMMENT 'Deprecated/unused column. NULL for most rows ג€” not reliably populated. Do not use. (Tier 5 ג€” domain expert)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `ProxyType` COMMENT 'Proxy classification: DCH=datacenter, VPN=VPN, PUB=public proxy, SES=session proxy, TOR=Tor exit node, WEB=web proxy. NULL for non-proxy connections. (Tier 1 ג€” STS)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `RealCID` COMMENT 'Real-account Customer ID. HASH distribution key. References `Dim_Customer.RealCID`. Each customer has one real CID. (Tier 1 ג€” Customer.CustomerStatic)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `RedeemID` COMMENT 'Billing.Redeem reference when position closed via redeem. (Tier 1 ג€” Trade.PositionTbl)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `RedeemStatus` COMMENT 'Redemption state. Billing.Redeem integration. (Tier 1 ג€” Trade.PositionTbl)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `RegulationIDOnOpen` COMMENT 'Regulatory jurisdiction ID at time of position open. ETL-computed via JOIN to etoro_History_BackOfficeCustomer (customer''s regulation history). ISNULL(..., 0) when no regulation match found. (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `ReopenForPositionID` COMMENT 'When position was reopened: references the erroneously closed PositionID. (Tier 1 ג€” Trade.PositionTbl)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `SessionID` COMMENT 'STS session identifier for logins and position opens. For manual opens: from login session. For copy opens: from mirror session. NULL for other events. (Tier 1 ג€” STS)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `SettlementTypeID` COMMENT 'Modern settlement classification. Dictionary.SettlementTypes: 0=CFD, 1=REAL, 2=TRS, 3=CMT, 4=REAL_FUTURES, 5=MARGIN_TRADE. Replaces IsSettled. (Tier 1 ג€” Trade.PositionTbl)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `StatusID` COMMENT 'Row status. Nearly always 1 (active). NULL for ~2M rows. (Tier 3 ג€” ETL-assigned)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `TicketFeeAction` COMMENT 'Human-readable description. Populated mainly for ActionTypeID=35 (fees): "Over night fee", "Payment caused by dividend", "Weekend fee", "OpenTotalFees", "CloseTotalFees", "SDRT Charge". For ActionTypeID=32: "edit stop loss by customer". For deposits: "Processed By eToro.Payments.Deposit", etc. (Tier 1 ג€” History.Credit, added 2024-08)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `TimeID` COMMENT 'Hour of the action (0-23). Derived from `DATEPART(HOUR, Occurred)`. (Tier 2 ג€” ETL-computed)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `UpdateDate` COMMENT 'UTC timestamp of the last DWH ETL update for this row. Set to `GETUTCDATE()` during each ETL run. (Tier 2 ג€” ETL-assigned)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `WithdrawID` COMMENT 'Withdrawal request ID for cashout events. 0 for non-cashout events. (Tier 1 ג€” History.Credit)';
ALTER TABLE main.etoro_kpi_prep.v_fact_customeraction_enriched ALTER COLUMN `WithdrawPaymentID` COMMENT 'Payment processing ID for cashout/withdrawal events. 0 for non-cashout events. Used to deduplicate WithdrawProcessingID rows in the ETL. (Tier 1 ג€” History.Credit)';

-- ----------------------------------------
-- main.etoro_kpi_prep.v_instrument_conversion_rates_dwh (10 columns)
-- ----------------------------------------
ALTER TABLE main.etoro_kpi_prep.v_instrument_conversion_rates_dwh ALTER COLUMN `ConversionRate_Buy` COMMENT 'Raw bid price before spread adjustment. Mid-price reference. Compare to BidSpreaded to derive the spread. (Tier 2 - SP_Fact_CurrencyPriceWithSplit_DL_To_Synapse)';
ALTER TABLE main.etoro_kpi_prep.v_instrument_conversion_rates_dwh ALTER COLUMN `ConversionRate_Buy_Spreaded` COMMENT 'Spread-adjusted bid price for the instrument. The bid price with the broker spread applied. Used in P&L calculations for sell-side closing proceeds. (Tier 2 - SP_Fact_CurrencyPriceWithSplit_DL_To_Synapse)';
ALTER TABLE main.etoro_kpi_prep.v_instrument_conversion_rates_dwh ALTER COLUMN `ConversionRate_Sell` COMMENT 'The buy-side asset of the instrument pair. FK to DWH_dbo.Dim_Currency(CurrencyID). For forex: the base currency. For stocks/ETFs/crypto: the asset''s own CurrencyID in Dim_Currency (BuyCurrencyID = InstrumentID for stocks). (Tier 1 -- upstream wiki, Trade.Instrument)';
ALTER TABLE main.etoro_kpi_prep.v_instrument_conversion_rates_dwh ALTER COLUMN `ConversionRate_Sell_Spreaded` COMMENT 'Spread-adjusted ask (offer) price for the instrument. The ask price with the broker spread applied. Used in P&L calculations for buy-side opening cost. (Tier 2 - SP_Fact_CurrencyPriceWithSplit_DL_To_Synapse)';
ALTER TABLE main.etoro_kpi_prep.v_instrument_conversion_rates_dwh ALTER COLUMN `InstrumentDisplayName` COMMENT 'User-facing instrument display name from Trade.InstrumentMetaData. More descriptive than Name (e.g., ''Apple Inc.'' vs ''Apple''). NULL for instruments without metadata entries. (Tier 2 -- SP_Dim_Instrument, etoro_Trade_InstrumentMetaData)';
ALTER TABLE main.etoro_kpi_prep.v_instrument_conversion_rates_dwh ALTER COLUMN `InstrumentID` COMMENT 'Primary key identifying the tradeable instrument pair. Allocated by Trade.InstrumentAdd during instrument creation. Ranges from 0 (system placeholder) to ~21 million IDs allocated. Referenced by virtually every trading fact table and the Dim_Currency / Dim_HistorySplitRatio dimension tables. (Tier 1 -- upstream wiki, Trade.Instrument)';
ALTER TABLE main.etoro_kpi_prep.v_instrument_conversion_rates_dwh ALTER COLUMN `InstrumentType` COMMENT 'Text label for InstrumentTypeID -- DWH-computed via CASE: 1=Currencies, 2=Commodities, 4=Indices, 5=Stocks, 6=ETF, 10=Crypto Currencies, else=Other. Use InstrumentTypeID for filtering; InstrumentType for display. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.etoro_kpi_prep.v_instrument_conversion_rates_dwh ALTER COLUMN `InstrumentTypeID` COMMENT 'Instrument type category: 1=Currencies (forex), 2=Commodities, 4=Indices, 5=Stocks, 6=ETF, 10=Crypto Currencies. Note TypeIDs 3, 7, 8, 9 are unused gaps. Distribution: Stocks 82%, ETF 8%, Crypto 4%, Commodities 3%, Indices 2%, Currencies 1%. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.etoro_kpi_prep.v_instrument_conversion_rates_dwh ALTER COLUMN `Name` COMMENT 'Instrument name as defined in Trade.Instrument. For forex: pair notation (e.g., EUR/USD). For stocks: company name (e.g., Apple, Alphabet). For crypto: token name. This is the internal instrument name, not necessarily the display name shown to users (see InstrumentDisplayName). (Tier 3 -- live data, etoro.Trade.GetInstrument)';
ALTER TABLE main.etoro_kpi_prep.v_instrument_conversion_rates_dwh ALTER COLUMN `SellCurrency` COMMENT 'Text abbreviation of SellCurrencyID -- denormalized from Dictionary.Currency.Abbreviation. Example: USD, EUR, GBX (GBP pence). DWH-added for query convenience. (Tier 2 -- SP_Dim_Instrument)';

-- ----------------------------------------
-- main.etoro_kpi_prep.v_mimo_allplatforms (21 columns)
-- ----------------------------------------
ALTER TABLE main.etoro_kpi_prep.v_mimo_allplatforms ALTER COLUMN `AmountOrigCurrency` COMMENT 'Transaction amount in original currency. Passthrough from sub-platform tables. `-1` sentinel for MoneyFarm (original amount unavailable). Negative for withdrawals on TP. (Tier 2 ג€” SP_DDR_Fact_Fact_MIMO_AllPlatforms)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_allplatforms ALTER COLUMN `AmountUSD` COMMENT 'Transaction amount in USD equivalent. Passthrough from sub-platform tables. Negative values may appear for withdrawals depending on platform source. (Tier 2 ג€” SP_DDR_Fact_Fact_MIMO_AllPlatforms)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_allplatforms ALTER COLUMN `Currency` COMMENT 'Currency ISO code. Passthrough from sub-platform tables. `''GBP''` hardcoded for MoneyFarm. (Tier 2 ג€” SP_DDR_Fact_Fact_MIMO_AllPlatforms)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_allplatforms ALTER COLUMN `CurrencyID` COMMENT 'Currency identifier. Passthrough from sub-platform tables. `3` (GBP) hardcoded for MoneyFarm. JOIN to `DWH_dbo.Dim_Currency`. (Tier 2 ג€” SP_DDR_Fact_Fact_MIMO_AllPlatforms)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_allplatforms ALTER COLUMN `Date` COMMENT 'Calendar date corresponding to DateID. `@date` SP input parameter. (Tier 2 ג€” SP_DDR_Fact_Fact_MIMO_AllPlatforms)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_allplatforms ALTER COLUMN `DateID` COMMENT 'Date key in YYYYMMDD integer format. Partition/filter key for daily DELETE/INSERT (TP+eMoney). Direct passthrough from sub-platform tables. (Tier 2 ג€” SP_DDR_Fact_Fact_MIMO_AllPlatforms)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_allplatforms ALTER COLUMN `FundingTypeID` COMMENT 'Payment method identifier. Passthrough from sub-platform tables. `-1` sentinel for MoneyFarm. JOIN to `DWH_dbo.Dim_FundingType` for name. `FundingTypeID = 27` triggers C2USD UPDATE for TP. (Tier 2 ג€” SP_DDR_Fact_Fact_MIMO_AllPlatforms)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_allplatforms ALTER COLUMN `IsCryptoToFiat` COMMENT 'Crypto-to-fiat deposit flag. `ISNULL(f.IsCryptoToFiat, 0)` from sub-platform tables; additionally `UPDATE SET IsCryptoToFiat=1 WHERE FundingTypeID=27 AND MIMOPlatform=''TradingPlatform'' AND DateID >= 20250701`. Dual-source indicator. (Tier 2 ג€” SP_DDR_Fact_Fact_MIMO_AllPlatforms)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_allplatforms ALTER COLUMN `IsGlobalFTD` COMMENT 'Cross-platform first-time deposit flag. `CASE WHEN f.RealCID IS NOT NULL THEN 1 ELSE 0 END` from LEFT JOIN to `Function_MIMO_First_Deposit_All_Platforms`; `ISNULL(...,0)`. Updated by FTD recovery UPDATEs from `Dim_Customer` for DateID >= 20250901. (Tier 2 ג€” SP_DDR_Fact_Fact_MIMO_AllPlatforms)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_allplatforms ALTER COLUMN `IsIBANQuickTransfer` COMMENT 'eMoney internal transfer flag (MoveMoneyReasonID = 6). `ISNULL(f.IsIBANQuickTransfer, 0)`. 1 = eMoney "Internal Transfer" feature (distinct from TP internal transfers). Always 0 for Options/MoneyFarm. (Tier 2 ג€” SP_DDR_Fact_Fact_MIMO_AllPlatforms)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_allplatforms ALTER COLUMN `IsInternalTransfer` COMMENT 'Internal fund transfer flag. `ISNULL(f.IsInternalTransfer, 0)`. 1 = transfer between platforms (TPג†”eMoney), not an external deposit/withdrawal. (Tier 2 ג€” SP_DDR_Fact_Fact_MIMO_AllPlatforms)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_allplatforms ALTER COLUMN `IsPlatformFTD` COMMENT 'Platform-level first-time deposit flag. `ISNULL(f.IsPlatformFTD, 0)`. Renamed from `IsFTD` in sub-platform tables. 1 = first deposit on this specific platform. Updated by FTD recovery logic for DateID >= 20250901. (Tier 2 ג€” SP_DDR_Fact_Fact_MIMO_AllPlatforms)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_allplatforms ALTER COLUMN `IsRecurring` COMMENT 'Recurring deposit flag. `ISNULL(f.IsRecurring, 0)`. 1 = deposit made via recurring/auto-deposit feature. Always 0 for Options/MoneyFarm. (Tier 2 ג€” SP_DDR_Fact_Fact_MIMO_AllPlatforms)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_allplatforms ALTER COLUMN `IsRedeem` COMMENT 'eMoney redemption flag. `ISNULL(f.IsRedeem, 0)`. 1 = eMoney balance redeemed to bank account. Always 0 for Options/MoneyFarm. (Tier 2 ג€” SP_DDR_Fact_Fact_MIMO_AllPlatforms)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_allplatforms ALTER COLUMN `IsTradeFromIBAN` COMMENT 'eMoney-initiated trade flag. `ISNULL(f.IsIBANTrade, 0)`. Renamed from `IsIBANTrade` in sub-platform tables. 1 = deposit originated from eMoney IBAN. Always 0 for Options/MoneyFarm. (Tier 2 ג€” SP_DDR_Fact_Fact_MIMO_AllPlatforms)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_allplatforms ALTER COLUMN `MIMOAction` COMMENT 'Transaction direction. `''Deposit''` for money in, `''Withdraw''` for money out. Passthrough from sub-platform tables. (Tier 2 ג€” SP_DDR_Fact_Fact_MIMO_AllPlatforms)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_allplatforms ALTER COLUMN `MIMOPlatform` COMMENT 'Platform discriminator. Literal: `''TradingPlatform''`, `''eMoney''`, `''Options''`, `''MoneyFarm''`. Set by SP during UNION/INSERT logic. (Tier 2 ג€” SP_DDR_Fact_Fact_MIMO_AllPlatforms)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_allplatforms ALTER COLUMN `OrigIdentifier` COMMENT 'Type label for the source transaction ID. Values: `''TransactionID''` (eMoney deposit), `''WithdrawPaymentID''` (withdrawal), `''DepositID''` (TP deposit/MoneyFarm). Passthrough from sub-platform tables. (Tier 2 ג€” SP_DDR_Fact_Fact_MIMO_AllPlatforms)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_allplatforms ALTER COLUMN `RealCID` COMMENT 'Customer identifier. Distribution key. Passthrough from sub-platform tables. (Tier 2 ג€” SP_DDR_Fact_Fact_MIMO_AllPlatforms)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_allplatforms ALTER COLUMN `TransactionID` COMMENT 'Source transaction identifier. `CAST(f.TransactionID AS VARCHAR(50))` for TP/eMoney; hardcoded `0` for Options and MoneyFarm (varchar incompatibility with lake schemas). (Tier 2 ג€” SP_DDR_Fact_Fact_MIMO_AllPlatforms)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_allplatforms ALTER COLUMN `UpdateDate` COMMENT 'ETL load timestamp. `GETDATE()` at SP execution time. (Tier 2 ג€” SP_DDR_Fact_Fact_MIMO_AllPlatforms)';

