ALTER TABLE main.etoro_kpi_prep.v_mimo_first_deposit_all_platforms ALTER COLUMN `DepositID` COMMENT 'Platform/account type of the first deposit (AccountTypeId from source). Added 2025-09-12. (Tier 2 ג€” SP_Dim_Customer)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_first_deposit_all_platforms ALTER COLUMN `FirstDepositAmount` COMMENT 'Amount of first deposit (in USD). Updated from FTDAmountInUsd. (Tier 2 ג€” SP_Dim_Customer)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_first_deposit_all_platforms ALTER COLUMN `FirstDepositDate` COMMENT 'Date of first deposit. DEFAULT=''19000101''. Updated from CustomerFinanceDB FTD data with FTDRecoveryDate logic. (Tier 2 ג€” SP_Dim_Customer)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_first_deposit_all_platforms ALTER COLUMN `FTDPlatform` COMMENT 'Platform/account type of the first deposit (AccountTypeId from source). Added 2025-09-12. (Tier 2 ג€” SP_Dim_Customer)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_first_deposit_all_platforms ALTER COLUMN `FTDPlatformID` COMMENT 'Platform/account type of the first deposit (AccountTypeId from source). Added 2025-09-12. (Tier 2 ג€” SP_Dim_Customer)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_first_deposit_all_platforms ALTER COLUMN `RealCID` COMMENT 'Customer ID - platform-internal primary key. Assigned at registration. Unique within etoro DB. Used as the universal customer identifier across all tables. (Tier 1 ג€” Customer.CustomerStatic)';

