ALTER TABLE main.etoro_kpi_prep.v_mimo_options_platform ALTER COLUMN `IsCreditReportValidCB` COMMENT 'DWH-computed: similar to IsValidCustomer but with additional AccountTypeIDג‰ 2 exclusion and specific CID exceptions for CountryID=250. (Tier 2 ג€” SP_Dim_Customer)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_options_platform ALTER COLUMN `IsGlobalFTD` COMMENT 'Customer ID - platform-internal primary key. Assigned at registration. Unique within etoro DB. Used as the universal customer identifier across all tables. (Tier 1 ג€” Customer.CustomerStatic)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_options_platform ALTER COLUMN `IsValidCustomer` COMMENT 'DWH-computed: 1 when not Popular Investor (PlayerLevelIDג‰ 4), not label 30/26, and not CountryID=250. Used in reporting to filter out non-standard customers. (Tier 2 ג€” SP_Dim_Customer)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_options_platform ALTER COLUMN `RealCID` COMMENT 'Customer ID - platform-internal primary key. Assigned at registration. Unique within etoro DB. Used as the universal customer identifier across all tables. (Tier 1 ג€” Customer.CustomerStatic)';

