-- ----------------------------------------
ALTER TABLE main.etoro_kpi_prep.v_mimo_optionsplatform ALTER COLUMN `IsCreditReportValidCB` COMMENT 'DWH-computed: similar to IsValidCustomer but with additional AccountTypeIDג‰ 2 exclusion and specific CID exceptions for CountryID=250. (Tier 2 ג€” SP_Dim_Customer)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_optionsplatform ALTER COLUMN `IsGlobalFTD` COMMENT 'Customer ID - platform-internal primary key. Assigned at registration. Unique within etoro DB. Used as the universal customer identifier across all tables. (Tier 1 ג€” Customer.CustomerStatic)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_optionsplatform ALTER COLUMN `IsValidCustomer` COMMENT 'DWH-computed: 1 when not Popular Investor (PlayerLevelIDג‰ 4), not label 30/26, and not CountryID=250. Used in reporting to filter out non-standard customers. (Tier 2 ג€” SP_Dim_Customer)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_optionsplatform ALTER COLUMN `RealCID` COMMENT 'Customer ID - platform-internal primary key. Assigned at registration. Unique within etoro DB. Used as the universal customer identifier across all tables. (Tier 1 ג€” Customer.CustomerStatic)';

-- ----------------------------------------
-- main.etoro_kpi_prep.v_mimo_tradingplatform (14 columns)
-- ----------------------------------------
ALTER TABLE main.etoro_kpi_prep.v_mimo_tradingplatform ALTER COLUMN `AmountOrigCurrency` COMMENT 'Exchange rate applied to convert from withdrawal currency to ProcessCurrencyID. NULL for same-currency payouts. (Tier 1 ג€” Billing.WithdrawToFunding)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_tradingplatform ALTER COLUMN `AmountUSD` COMMENT 'Position size in currency. Must be >= 0. Stored in dollars (PositionOpen divides by 100 from cents). (Tier 1 ג€” Trade.PositionTbl)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_tradingplatform ALTER COLUMN `CurrencyID` COMMENT 'Currency used for the actual payment processing. May differ from withdrawal CurrencyID when cross-currency routing is applied. FK to Dim_Currency. (Tier 1 ג€” Billing.WithdrawToFunding)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_tradingplatform ALTER COLUMN `Date` COMMENT 'Date of the action as integer YYYYMMDD. Derived from `Occurred`. Part of nonclustered indexes. (Tier 2 ג€” ETL-computed)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_tradingplatform ALTER COLUMN `DateID` COMMENT 'Date of the action as integer YYYYMMDD. Derived from `Occurred`. Part of nonclustered indexes. (Tier 2 ג€” ETL-computed)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_tradingplatform ALTER COLUMN `FundingTypeID` COMMENT 'Payment method type of the funding instrument receiving the payout. Renamed from FundingTypeID on Billing.Funding. 34 distinct types (Visa/MC/Neteller/PayPal/Wire/eToroMoney/etc.). FK to Dim_FundingType. (Tier 1 ג€” Billing.Funding)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_tradingplatform ALTER COLUMN `IsFTD` COMMENT 'Deposit transaction identifier. NULL for non-deposit events. (Tier 1 ג€” History.Credit)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_tradingplatform ALTER COLUMN `IsIBANQuickTransfer` COMMENT 'Reason for money movement: 1=Adjustment, 5=InternalTransfer Trade, 6=InternalTransfer, 8=Recurring Deposit, 9=Recurring Investment. References `Dictionary.MoveMoneyReason`. (Tier 1 ג€” History.Credit)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_tradingplatform ALTER COLUMN `IsIBANTrade` COMMENT 'Event type classifier. References `DWH_dbo.Dim_ActionType.ActionTypeID` ג€” JOIN for Name, Category, CategoryID. See Section 2.1 for full mapping. Key filter column ג€” drives which other columns are populated. (Tier 1 ג€” ETL-derived from CreditTypeID/source)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_tradingplatform ALTER COLUMN `IsInternalTransfer` COMMENT 'Type of payment instrument. Sourced from Billing.Funding.FundingTypeID (not from Billing.Deposit directly). Categorizes the deposit by payment method (credit card, wire, ACH, etc.). (Tier 2 ג€” SP_Fact_BillingDeposit_DL_To_Synapse)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_tradingplatform ALTER COLUMN `IsRecurring` COMMENT '1=deposit is part of a recurring schedule (OUTER APPLY on Billing.RecurringDeposit). 0=one-time deposit. (Tier 2 ג€” SP_Fact_BillingDeposit_DL_To_Synapse)';
ALTER TABLE main.etoro_kpi_prep.v_mimo_tradingplatform ALTER COLUMN `IsRedeem` COMMENT 'Redeem flag. 0=not a redeem, 1=is a redeem. NULL for non-position events. Same meaning as `Dim_Position.IsRedeem` (via RedeemStatus mapping). (Tier 3 ג€” ETL-derived)';
