ALTER TABLE main.etoro_kpi_prep.v_population_active_traders ALTER COLUMN `ActiveTradedETFCFD` COMMENT 'FK to Trade.Mirror. 0/NULL = manual. Positive = copy-trade position. (Tier 1 ג€” Trade.PositionTbl)';
