ALTER TABLE main.etoro_kpi_prep.v_population_active_traders ALTER COLUMN `ActiveTradedStocksReal` COMMENT 'FK to Trade.Mirror. 0/NULL = manual. Positive = copy-trade position. (Tier 1 ג€” Trade.PositionTbl)';
ALTER TABLE main.etoro_kpi_prep.v_population_active_traders ALTER COLUMN `DateID` COMMENT 'Date of the action as integer YYYYMMDD. Derived from `Occurred`. Part of nonclustered indexes. (Tier 2 ג€” ETL-computed)';
ALTER TABLE main.etoro_kpi_prep.v_population_active_traders ALTER COLUMN `GCID` COMMENT 'Global Customer ID ג€” the platform-wide unique customer identifier. References `Dim_Customer.GCID`. (Tier 1 ג€” Customer.CustomerStatic)';
