ALTER TABLE main.etoro_kpi_prep.v_population_first_time_funded ALTER COLUMN `FirstVerifiedDate` COMMENT 'Start date of the customer snapshot range (YYYYMMDD integer). (Tier 2 ג€” view DDL)';
