ALTER TABLE main.etoro_kpi_stg.bi_output_vg_aum_slim ALTER COLUMN `CashInCopy` COMMENT 'Cash allocated to copy trades. From V_Liabilities.TotalMirrorCash ג€” total mirror cash held by copiers. (Tier 1 ג€” DWH_dbo.V_Liabilities)';
