ALTER TABLE main.etoro_kpi_stg.bi_output_vg_aum_slim ALTER COLUMN `EquityTradingPlatform` COMMENT 'Trading Platform total equity. SUM(ISNULL(TotalLiability,0) + ISNULL(actualNWA,0)) from BI_DB_Client_Balance_CID_Level_New. (Tier 2 ג€” SP_DDR_Fact_AUM)';
ALTER TABLE main.etoro_kpi_stg.bi_output_vg_aum_slim ALTER COLUMN `InvestedAmountCopy` COMMENT 'Invested amount in copy (excl cash). TotalMirrorPositionsAmount + TotalMirrorStockOrders + CopyPositionPnL from V_Liabilities. (Tier 2 ג€” SP_DDR_Fact_AUM)';
