ALTER TABLE main.etoro_kpi_stg.bi_output_vg_aum_slim ALTER COLUMN `InvestedAmountStocksManual` COMMENT 'Manual stock invested amount (excl PnL). TotalStockPositionAmount + TotalStockOrders גˆ’ TotalMirrorStockPositionAmount. (Tier 2 ג€” SP_DDR_Fact_AUM)';
ALTER TABLE main.etoro_kpi_stg.bi_output_vg_aum_slim ALTER COLUMN `OptionsTotalEquity` COMMENT 'Options platform total equity from Apex buy-power summary. From Function_AUM_OptionsPlatform ג†’ External_Sodreconciliation_apex_EXT981_BuyPowerSummary.TotalEquity. Uses latest available Apex date ג‰₪ @dateID. Excludes house accounts (4GS43999, 4GS00100-104). (Tier 2 ג€” SP_DDR_Fact_AUM)';
ALTER TABLE main.etoro_kpi_stg.bi_output_vg_aum_slim ALTER COLUMN `RealCID` COMMENT 'Real customer ID. COALESCE(cb.CID, i.CID, ob.RealCID) across TP, IBAN, and Options sources. HASH distribution key. (Tier 2 ג€” SP_DDR_Fact_AUM)';
ALTER TABLE main.etoro_kpi_stg.bi_output_vg_aum_slim ALTER COLUMN `RealizedEquityGlobal` COMMENT 'Global realized equity. RealizedEquityTP + IBANBalance. Options excluded because options cannot differentiate invested vs PnL. (Tier 2 ג€” SP_DDR_Fact_AUM)';
ALTER TABLE main.etoro_kpi_stg.bi_output_vg_aum_slim ALTER COLUMN `RealizedEquityTradingPlatform` COMMENT 'Trading Platform realized equity. SUM(realizedEquity) from BI_DB_Client_Balance_CID_Level_New per CID/DateID. (Tier 2 ג€” SP_DDR_Fact_AUM)';
ALTER TABLE main.etoro_kpi_stg.bi_output_vg_aum_slim ALTER COLUMN `TotalInvestedAmount` COMMENT 'Total invested amount (renamed from PositionAmount). SUM(PositionAmount) from BI_DB_Client_Balance_CID_Level_New. (Tier 2 ג€” SP_DDR_Fact_AUM)';
ALTER TABLE main.etoro_kpi_stg.bi_output_vg_aum_slim ALTER COLUMN `TotalPositionPNL` COMMENT 'Total position PnL (renamed from PositionPNL). SUM(PositionPNL) from BI_DB_Client_Balance_CID_Level_New. (Tier 2 ג€” SP_DDR_Fact_AUM)';

